export const SETUP_BASH_COMMON_OUTPUT = "# Floway Agent Setup common installer fragment (Bash 3.2+). TypeScript prepends\n# the language-native assignment prefix and appends one agent fragment.\n#\n# Each served script targets exactly one agent. Errexit stays disabled because\n# Bash suppresses it inside guarded calls; failures are checked explicitly and\n# the selected agent's configuration is rolled back as one transaction.\n\n# --- output layer -----------------------------------------------------------\n#\n# Setup-owned output follows Homebrew's compact visual language: blue `==>`\n# notices introduce major phases, while warnings and errors color only their\n# labels. Phase details remain subordinate instead of competing for attention.\n# Native package managers inherit the terminal directly, so their ANSI colors,\n# carriage-return progress, buffering, and cursor behavior remain intact.\n#\n# Color is emitted only for an interactive terminal with NO_COLOR unset, probed\n# per stream so a redirected capture on either stdout or stderr stays free of\n# escape sequences. Agent notices and informational lines go to stdout;\n# warnings, errors, and rollback notices go to stderr.\n_stream_color() {\n  [ -z \"${NO_COLOR:-}\" ] || return 1\n  [ -n \"${AGENT_SETUP_TEST_FORCE_COLOR:-}\" ] && return 0\n  [ -t \"$1\" ]\n}\n_init_output() {\n  if _stream_color 1; then _OUT_COLOR=1; else _OUT_COLOR=0; fi\n  if _stream_color 2; then _ERR_COLOR=1; else _ERR_COLOR=0; fi\n  _C_BLUE=$'\\033[34m'\n  _C_BOLD=$'\\033[1m'\n  _C_YELLOW=$'\\033[93m'\n  _C_RED=$'\\033[91m'\n  _C_RESET=$'\\033[0m'\n}\n\n_emit_notice() {\n  if [ \"$_OUT_COLOR\" -eq 1 ]; then\n    printf '%s==>%s %s%s%s\\n' \"$_C_BLUE\" \"$_C_RESET\" \"$_C_BOLD\" \"$1\" \"$_C_RESET\"\n  else\n    printf '==> %s\\n' \"$1\"\n  fi\n}\n\n# Homebrew colors the diagnostic label rather than the whole message, keeping\n# paths and remediation text readable in the terminal's native foreground.\n_emit_diagnostic() {\n  if [ \"$_ERR_COLOR\" -eq 1 ]; then\n    printf '%s%s:%s %s\\n' \"$1\" \"$2\" \"$_C_RESET\" \"$3\" >&2\n  else\n    printf '%s: %s\\n' \"$2\" \"$3\" >&2\n  fi\n}\n\n# Default-color detail lines stay uncolored rather than carrying a bare reset.\n# $1 stream (1|2), $2 color, $3 text.\n_emit_line() {\n  if [ \"$1\" -eq 1 ]; then\n    if [ \"$_OUT_COLOR\" -eq 1 ] && [ -n \"$2\" ]; then printf '%s%s%s\\n' \"$2\" \"$3\" \"$_C_RESET\"; else printf '%s\\n' \"$3\"; fi\n  else\n    if [ \"$_ERR_COLOR\" -eq 1 ] && [ -n \"$2\" ]; then printf '%s%s%s\\n' \"$2\" \"$3\" \"$_C_RESET\" >&2; else printf '%s\\n' \"$3\" >&2; fi\n  fi\n}\n\nout_agent_notice() { _emit_notice \"$1: $2\"; }\nout_metadata() { _emit_line 1 '' \"$1: $2\"; }\nout_info() { _emit_line 1 '' \"$1\"; }\nout_warn() { _emit_diagnostic \"$_C_YELLOW\" 'Warning' \"$1\"; }\nout_error() { _emit_diagnostic \"$_C_RED\" 'Error' \"$1\"; }\n\nSETUP_TMPDIR=\"\"\n_cleanup() {\n  if [ -n \"$SETUP_TMPDIR\" ]; then\n    rm -rf \"$SETUP_TMPDIR\" 2>/dev/null || true\n  fi\n}\n# EXIT owns cleanup. INT/TERM only translate the signal into the conventional\n# exit status (130 = 128+SIGINT, 143 = 128+SIGTERM) and let that exit fire the\n# EXIT trap. Cleaning up directly inside the INT/TERM handlers would delete the\n# working directory and then let the interrupted script resume into the next\n# agent's configuration; exiting instead stops all further agent work.\n";

export const SETUP_BASH_COMMON_HELPERS = "# Run a command under a wall-clock limit. macOS ships no `timeout`, so the\n# Bash-3.2 fallback enables job control for one launch, placing the command and\n# all ordinary descendants in a dedicated process group. The watchdog signals\n# that group with TERM then KILL, retains its process-group id across root exit,\n# and the parent waits for escalation to finish before returning 124.\n_run_with_timeout() {\n  _rwt_secs=$1\n  shift\n  if command -v timeout >/dev/null 2>&1; then\n    timeout \"$_rwt_secs\" \"$@\"\n    return $?\n  fi\n  if command -v gtimeout >/dev/null 2>&1; then\n    gtimeout \"$_rwt_secs\" \"$@\"\n    return $?\n  fi\n\n  _rwt_marker=$(mktemp \"$SETUP_TMPDIR/timeout.XXXXXX\") || return 1\n  rm -f \"$_rwt_marker\"\n  if [ -n \"${AGENT_SETUP_TEST_TRACE_TIMEOUT:-}\" ]; then\n    printf 'Agent Setup test: timeout fallback: process-tree\\n'\n  fi\n  set -m\n  \"$@\" &\n  _rwt_pid=$!\n  set +m\n  (\n    # The watchdog must not retain the installer's stdout/stderr descriptors\n    # after its parent shell is killed; otherwise a pipe consumer waits for the\n    # orphaned sleep to exit before receiving EOF.\n    exec </dev/null >/dev/null 2>&1\n    sleep \"$_rwt_secs\"\n    if kill -0 \"$_rwt_pid\" 2>/dev/null; then\n      : > \"$_rwt_marker\"\n      kill -TERM -- \"-$_rwt_pid\" 2>/dev/null || true\n      sleep 1\n      kill -KILL -- \"-$_rwt_pid\" 2>/dev/null || true\n    fi\n  ) &\n  _rwt_watchdog=$!\n  wait \"$_rwt_pid\"\n  _rwt_status=$?\n  if [ -e \"$_rwt_marker\" ]; then\n    # Let TERM→KILL escalation finish before reporting the timeout.\n    wait \"$_rwt_watchdog\" 2>/dev/null || true\n    rm -f \"$_rwt_marker\"\n    return 124\n  fi\n  kill \"$_rwt_watchdog\" 2>/dev/null || true\n  wait \"$_rwt_watchdog\" 2>/dev/null || true\n  rm -f \"$_rwt_marker\"\n  return $_rwt_status\n}\n\n# jq handle, resolved by ensure_jq before any configuration file is touched.\nJQ=\"\"\n\n# Download the pinned official jq build for this platform into the private\n# working directory and verify its hard-coded SHA-256 before use. Fails on an\n# unsupported platform, a download error, a missing hashing tool, or a checksum\n# mismatch — always before any configuration file is touched.\n_bootstrap_jq() {\n  _bj_os=$(uname -s)\n  _bj_arch=$(uname -m)\n  case \"$_bj_os\" in\n    Darwin) _bj_os_part=macos ;;\n    Linux) _bj_os_part=linux ;;\n    *) out_error \"no pinned jq build for OS $_bj_os.\"; return 1 ;;\n  esac\n  case \"$_bj_arch\" in\n    x86_64 | amd64) _bj_arch_part=amd64 ;;\n    arm64 | aarch64) _bj_arch_part=arm64 ;;\n    *) out_error \"no pinned jq build for architecture $_bj_arch.\"; return 1 ;;\n  esac\n  _bj_asset=\"jq-$_bj_os_part-$_bj_arch_part\"\n  # Pinned to jqlang/jq release jq-1.8.2. Each digest was verified against the\n  # release sha256sum.txt and the Sigstore build attestation\n  # (signer: jqlang/jq .github/workflows/ci.yml@refs/tags/jq-1.8.2).\n  # Ref: https://github.com/jqlang/jq/releases/tag/jq-1.8.2\n  case \"$_bj_asset\" in\n    jq-macos-amd64) _bj_sha=e94b266e3c26690550006abe63152b782280f4e14374accdf04cbde844f00bc0 ;;\n    jq-macos-arm64) _bj_sha=2d75340ba57a4b4b4c8708a21c2dc8e958a48aaa8bba13b27f77f6e4c0eca07e ;;\n    jq-linux-amd64) _bj_sha=b1c22172dd303f3be49e935aa56aa48a8b7a46e0bc838b4997d3bb451495870f ;;\n    jq-linux-arm64) _bj_sha=8b85c817833814ddca00a144c33705546355afccf0cf39b188f3cdb48b852309 ;;\n    *) return 1 ;;\n  esac\n  _bj_url=\"https://github.com/jqlang/jq/releases/download/jq-1.8.2/$_bj_asset\"\n  _bj_dest=\"$SETUP_TMPDIR/$_bj_asset\"\n  out_warn 'jq not found on PATH; fetching the pinned jq-1.8.2 build'\n  if ! curl -fsSL --connect-timeout 10 --max-time 120 -o \"$_bj_dest\" \"$_bj_url\"; then\n    out_error \"failed to download jq from $_bj_url\"\n    rm -f \"$_bj_dest\"\n    return 1\n  fi\n  if command -v sha256sum >/dev/null 2>&1; then\n    _bj_actual=$(sha256sum \"$_bj_dest\" | awk '{ print $1 }')\n  elif command -v shasum >/dev/null 2>&1; then\n    _bj_actual=$(shasum -a 256 \"$_bj_dest\" | awk '{ print $1 }')\n  elif command -v openssl >/dev/null 2>&1; then\n    _bj_actual=$(openssl dgst -sha256 \"$_bj_dest\" | awk '{ print $NF }')\n  else\n    _bj_actual=\"\"\n  fi\n  if [ -z \"$_bj_actual\" ]; then\n    out_error 'no SHA-256 tool available to verify the jq download.'\n    rm -f \"$_bj_dest\"\n    return 1\n  fi\n  if [ \"$_bj_actual\" != \"$_bj_sha\" ]; then\n    out_error 'jq checksum mismatch; refusing to use the download.'\n    rm -f \"$_bj_dest\"\n    return 1\n  fi\n  if ! chmod 700 \"$_bj_dest\"; then\n    rm -f \"$_bj_dest\"\n    return 1\n  fi\n  JQ=\"$_bj_dest\"\n}\n\n# Resolve a usable jq: prefer PATH, else provision the pinned build. The\n# AGENT_SETUP_TEST_NO_JQ_DOWNLOAD hook lets the test harness assert the\n# fail-before-mutation path without reaching the network.\nensure_jq() {\n  if command -v jq >/dev/null 2>&1; then\n    JQ=jq\n    return 0\n  fi\n  if [ -n \"${AGENT_SETUP_TEST_NO_JQ_DOWNLOAD:-}\" ]; then\n    return 1\n  fi\n  _bootstrap_jq\n}\n\n# Download an installer to the private working directory, refuse anything that\n# is not a shell script (region blocks and captive portals serve HTML in place\n# of the real installer), then execute it without sudo.\n_download_and_run_installer() {\n  _dri_url=$1\n  _dri_file=$(mktemp \"$SETUP_TMPDIR/install.XXXXXX\") || return 1\n  if ! curl -fsSL --connect-timeout 10 --max-time 120 -o \"$_dri_file\" \"$_dri_url\"; then\n    out_error \"could not download the installer from $_dri_url\"\n    rm -f \"$_dri_file\"\n    return 1\n  fi\n  # Reject common HTML responses while allowing official shell content with or\n  # without a shebang (some installer CDNs prepend comments).\n  if awk '\n      NR <= 20 {\n        line = tolower($0)\n        if (line ~ /^[[:space:]]*(<!doctype[[:space:]]+html|<html([[:space:]>])|<head([[:space:]>])|<body([[:space:]>]))/) found = 1\n      }\n      END { exit found ? 0 : 1 }\n    ' \"$_dri_file\"; then\n    out_error 'the installer download was HTML, not an executable script (a login or region-block page?).'\n    rm -f \"$_dri_file\"\n    return 1\n  fi\n  if ! awk 'NF { found = 1 } END { exit found ? 0 : 1 }' \"$_dri_file\"; then\n    out_error 'the installer download was empty.'\n    rm -f \"$_dri_file\"\n    return 1\n  fi\n  _dri_timeout=${AGENT_SETUP_TEST_TIMEOUT_SECONDS:-120}\n  _run_with_timeout \"$_dri_timeout\" env -u SETUP_API_KEY bash \"$_dri_file\" </dev/null\n  _dri_rc=$?\n  rm -f \"$_dri_file\"\n  return $_dri_rc\n}\n\n_discover_cli() {\n  _dc_name=$1\n  shift\n  DISCOVERED_BIN=$(command -v \"$_dc_name\" 2>/dev/null || true)\n  if [ -n \"$DISCOVERED_BIN\" ]; then\n    DISCOVERED_COUNT=1\n  else\n    DISCOVERED_COUNT=0\n  fi\n  for _dc_candidate in \"$@\"; do\n    [ -x \"$_dc_candidate\" ] || continue\n    [ \"$_dc_candidate\" = \"$DISCOVERED_BIN\" ] && continue\n    DISCOVERED_COUNT=$((DISCOVERED_COUNT + 1))\n    if [ -z \"$DISCOVERED_BIN\" ]; then\n      DISCOVERED_BIN=$_dc_candidate\n    fi\n  done\n}\n\n# Rollback retains a backup when restoration fails so manual recovery remains\n# possible. Callers keep separate transaction boundaries and aggregate failures.\n_restore_managed_file() {\n  _rmf_existed=$1\n  _rmf_backup=$2\n  _rmf_path=$3\n  _rmf_original_label=$4\n  _rmf_created_label=$5\n  if [ \"$_rmf_existed\" -eq 1 ]; then\n    if [ -n \"$_rmf_backup\" ] && [ -e \"$_rmf_backup\" ] && ! mv \"$_rmf_backup\" \"$_rmf_path\" 2>/dev/null; then\n      out_warn \"could not restore $_rmf_path from its backup; your original $_rmf_original_label is preserved at $_rmf_backup — restore it by hand.\"\n      return 1\n    fi\n  elif ! rm -f \"$_rmf_path\" 2>/dev/null; then\n    out_warn \"could not remove the $_rmf_created_label this run created at $_rmf_path — remove it by hand.\"\n    return 1\n  fi\n  return 0\n}\n\n_prune_managed_backups() {\n  _pmb_path=$1\n  _pmb_keep=$2\n  for _pmb_backup in \"$_pmb_path\".floway-backup.*; do\n    [ -e \"$_pmb_backup\" ] || continue\n    [ \"$_pmb_backup\" = \"$_pmb_keep\" ] && continue\n    if ! rm -f \"$_pmb_backup\"; then\n      out_error \"could not remove obsolete backup $_pmb_backup\"\n      return 1\n    fi\n  done\n}\n\n_install_brew_cask() {\n  _ibc_cask=$1\n  if ! command -v brew >/dev/null 2>&1; then\n    out_error 'Homebrew is required to install agent CLIs on macOS.'\n    return 1\n  fi\n  _ibc_timeout=${AGENT_SETUP_TEST_TIMEOUT_SECONDS:-600}\n  _run_with_timeout \"$_ibc_timeout\" env -u SETUP_API_KEY brew install --cask \"$_ibc_cask\" </dev/null\n}\n\n_install_npm_package() {\n  _inp_package=$1\n  _inp_timeout=${AGENT_SETUP_TEST_TIMEOUT_SECONDS:-600}\n  _run_with_timeout \"$_inp_timeout\" env -u SETUP_API_KEY npm install --global \"$_inp_package\" </dev/null\n}\n";

export const SETUP_BASH_COMMON_MAIN = "# --- run --------------------------------------------------------------------\n\nmain() {\n  set -u\n  umask 077\n  set -o pipefail 2>/dev/null || true\n\n  # Neutralize identically named exported variables inherited from the caller.\n  # jq receives the API key only on the exact invocations that need it; package\n  # managers and CLIs never inherit the credential.\n  export -n SETUP_API_KEY SETUP_API_KEY_NAME 2>/dev/null || true\n\n  _init_output\n  out_agent_notice 'Agent Setup' \"$1\"\n\n  if [ -z \"${SETUP_ENDPOINT:-}\" ]; then\n    out_error 'SETUP_ENDPOINT must be set to this gateway origin (e.g. https://gateway.example).'\n    return 1\n  fi\n  case \"$SETUP_ENDPOINT\" in\n    http://?* | https://?*) ;;\n    *) out_error \"SETUP_ENDPOINT must be an http(s) origin, got $SETUP_ENDPOINT\"; return 1 ;;\n  esac\n  out_metadata 'Endpoint' \"$SETUP_ENDPOINT\"\n  out_metadata 'API Key' \"$SETUP_API_KEY_NAME\"\n  export -n SETUP_ENDPOINT 2>/dev/null || true\n\n  SETUP_TMPDIR=$(mktemp -d \"${TMPDIR:-/tmp}/agent-setup.XXXXXX\") || {\n    out_error 'could not create a private working directory.'\n    return 1\n  }\n  chmod 700 \"$SETUP_TMPDIR\" 2>/dev/null || true\n  trap _cleanup EXIT\n  trap 'exit 130' INT\n  trap 'exit 143' TERM\n\n  configure_agent\n}\n";

export const SETUP_BASH_CLAUDE = "# Claude Code Agent Setup fragment.\n\n# Managed-key merge applied to the existing Claude settings document. Only the\n# keys the setup owns are touched; every unrelated key and env var is preserved.\n# An empty optional value means \"remove that managed key\". The API key is read\n# from the environment (`env.SETUP_API_KEY`) so it stays out of argv.\n# Refs: https://docs.claude.com/en/docs/claude-code/env-vars\n#       https://docs.claude.com/en/docs/claude-code/model-config#environment-variables\n#       https://docs.claude.com/en/docs/claude-code/settings\n#       https://code.claude.com/docs/en/settings#attribution-settings\nCLAUDE_MERGE_PROGRAM='\n  if type != \"object\" then error(\"root is not a JSON object\")\n  elif (has(\"env\") and ((.env | type) != \"object\")) then error(\"env is not a JSON object\")\n  elif (has(\"attribution\") and ((.attribution | type) != \"object\")) then error(\"attribution is not a JSON object\")\n  else . end\n  | (if (has(\"env\") | not) then .env = {} else . end)\n  | .env.ANTHROPIC_BASE_URL = $baseUrl\n  | .env.ANTHROPIC_AUTH_TOKEN = env.SETUP_API_KEY\n  | (if $model == \"\" then del(.env.ANTHROPIC_MODEL) else .env.ANTHROPIC_MODEL = $model end)\n  | (if $opus == \"\" then del(.env.ANTHROPIC_DEFAULT_OPUS_MODEL) else .env.ANTHROPIC_DEFAULT_OPUS_MODEL = $opus end)\n  | (if $sonnet == \"\" then del(.env.ANTHROPIC_DEFAULT_SONNET_MODEL) else .env.ANTHROPIC_DEFAULT_SONNET_MODEL = $sonnet end)\n  | (if $haiku == \"\" then del(.env.ANTHROPIC_DEFAULT_HAIKU_MODEL) else .env.ANTHROPIC_DEFAULT_HAIKU_MODEL = $haiku end)\n  | (if $discovery == \"1\" then .env.CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY = \"1\" else del(.env.CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY) end)\n  | (if $effort == \"\" then del(.effortLevel) else .effortLevel = $effort end)\n  | (if $cleanup == \"\" then del(.cleanupPeriodDays) else .cleanupPeriodDays = ($cleanup | tonumber) end)\n  | (if $optOutAttribution == \"1\" then\n      .attribution = ((.attribution // {}) + { \"commit\": \"\", \"pr\": \"\", \"sessionUrl\": false })\n    else\n      del(.attribution.commit, .attribution.pr, .attribution.sessionUrl)\n      | (if .attribution == {} then del(.attribution) else . end)\n    end)\n'\n\n# Refs:\n# https://code.claude.com/docs/en/setup\n# https://github.com/anthropics/claude-code/blob/c39cb0f14bfe8bb519bae5bfc55add6867c5e2ab/README.md#L13-L44\nclaude_ensure_installed() {\n  _discover_cli claude \\\n    \"$HOME/.local/bin/claude\" \\\n    \"$HOME/.claude/local/claude\" \\\n    \"$HOME/.bun/bin/claude\" \\\n    \"/opt/homebrew/bin/claude\" \\\n    \"/usr/local/bin/claude\"\n  CLAUDE_BIN=$DISCOVERED_BIN\n  if [ \"$DISCOVERED_COUNT\" -gt 1 ]; then\n    out_warn \"multiple Claude Code installations detected; using $CLAUDE_BIN\"\n  fi\n  if [ \"$DISCOVERED_COUNT\" -ge 1 ]; then\n    out_info 'Claude Code is already installed.'\n    return 0\n  fi\n\n  if [ -n \"${AGENT_SETUP_TEST_INSTALL_CLAUDE_SCRIPT:-}\" ]; then\n    out_info 'Claude Code CLI not found; running the test installer'\n    _ic_timeout=${AGENT_SETUP_TEST_TIMEOUT_SECONDS:-120}\n    _run_with_timeout \"$_ic_timeout\" env -u SETUP_API_KEY bash \"$AGENT_SETUP_TEST_INSTALL_CLAUDE_SCRIPT\" </dev/null || return 1\n  elif [ -n \"${AGENT_SETUP_TEST_CLAUDE_URL:-}\" ]; then\n    out_info 'Claude Code CLI not found; running the test installer download'\n    _download_and_run_installer \"$AGENT_SETUP_TEST_CLAUDE_URL\" || return 1\n  else\n    case \"$(uname -s)\" in\n      Darwin)\n        if command -v brew >/dev/null 2>&1; then\n          out_info 'Claude Code CLI not found; installing with Homebrew'\n          _install_brew_cask claude-code || return 1\n        elif command -v npm >/dev/null 2>&1; then\n          out_info 'Claude Code CLI not found; installing with npm'\n          _install_npm_package '@anthropic-ai/claude-code' || return 1\n        else\n          out_info 'Claude Code CLI not found; installing from downloads.claude.ai'\n          _download_and_run_installer 'https://downloads.claude.ai/claude-code-releases/bootstrap.sh' || return 1\n        fi\n        ;;\n      Linux)\n        if command -v npm >/dev/null 2>&1; then\n          out_info 'Claude Code CLI not found; installing with npm'\n          _install_npm_package '@anthropic-ai/claude-code' || return 1\n        else\n          out_info 'Claude Code CLI not found; installing from downloads.claude.ai'\n          _download_and_run_installer 'https://downloads.claude.ai/claude-code-releases/bootstrap.sh' || return 1\n        fi\n        ;;\n      *)\n        out_error 'automatic Claude Code installation supports macOS and Linux only in the Bash installer.'\n        return 1\n        ;;\n    esac\n  fi\n  hash -r 2>/dev/null || true\n  _discover_cli claude \\\n    \"$HOME/.local/bin/claude\" \\\n    \"$HOME/.claude/local/claude\" \\\n    \"$HOME/.bun/bin/claude\" \\\n    \"/opt/homebrew/bin/claude\" \\\n    \"/usr/local/bin/claude\"\n  CLAUDE_BIN=$DISCOVERED_BIN\n  [ \"$DISCOVERED_COUNT\" -ge 1 ]\n}\n\nclaude_rollback_settings() {\n  _restore_managed_file \\\n    \"${CLAUDE_SETTINGS_EXISTED:-0}\" \"${CLAUDE_SETTINGS_BACKUP:-}\" \"$CLAUDE_SETTINGS_PATH\" \\\n    \"file\" \"Claude settings\"\n}\n\n# Same-directory staging keeps the mode-0600 replacement rename atomic.\nclaude_write_settings() {\n  _cw_dir=\"${CLAUDE_CONFIG_DIR:-$HOME/.claude}\"\n  CLAUDE_SETTINGS_PATH=\"$_cw_dir/settings.json\"\n  CLAUDE_SETTINGS_BACKUP=\"\"\n  CLAUDE_SETTINGS_EXISTED=0\n\n  if ! mkdir -p \"$_cw_dir\"; then\n    out_error \"could not create $_cw_dir\"\n    return 1\n  fi\n\n  if [ -e \"$CLAUDE_SETTINGS_PATH\" ]; then\n    CLAUDE_SETTINGS_EXISTED=1\n    if ! \"$JQ\" '\n        if type != \"object\" then error(\"root is not a JSON object\")\n        elif (has(\"env\") and ((.env | type) != \"object\")) then error(\"env is not a JSON object\")\n        elif (has(\"attribution\") and ((.attribution | type) != \"object\")) then error(\"attribution is not a JSON object\")\n        else . end\n      ' \"$CLAUDE_SETTINGS_PATH\" >/dev/null 2>&1; then\n      out_error \"$CLAUDE_SETTINGS_PATH is not valid Claude settings; leaving it untouched.\"\n      return 1\n    fi\n    _cw_base=$(cat \"$CLAUDE_SETTINGS_PATH\")\n    CLAUDE_SETTINGS_BACKUP=\"$CLAUDE_SETTINGS_PATH.floway-backup.$(date +%Y%m%d%H%M%S).$$\"\n    if ! cp \"$CLAUDE_SETTINGS_PATH\" \"$CLAUDE_SETTINGS_BACKUP\"; then\n      out_error \"could not back up $CLAUDE_SETTINGS_PATH\"\n      return 1\n    fi\n  else\n    _cw_base='{}'\n  fi\n\n  _cw_stage=\"$CLAUDE_SETTINGS_PATH.floway-stage.$$\"\n  if ! printf '%s' \"$_cw_base\" | SETUP_API_KEY=\"$SETUP_API_KEY\" \"$JQ\" \\\n      --arg baseUrl \"$SETUP_ENDPOINT\" \\\n      --arg model \"$SETUP_CLAUDE_MODEL\" \\\n      --arg opus \"$SETUP_CLAUDE_DEFAULT_OPUS_MODEL\" \\\n      --arg sonnet \"$SETUP_CLAUDE_DEFAULT_SONNET_MODEL\" \\\n      --arg haiku \"$SETUP_CLAUDE_DEFAULT_HAIKU_MODEL\" \\\n      --arg discovery \"$SETUP_CLAUDE_MODEL_DISCOVERY\" \\\n      --arg effort \"$SETUP_CLAUDE_EFFORT_LEVEL\" \\\n      --arg cleanup \"$SETUP_CLAUDE_CLEANUP_PERIOD_DAYS\" \\\n      --arg optOutAttribution \"$SETUP_CLAUDE_OPT_OUT_AI_ATTRIBUTION\" \\\n      \"$CLAUDE_MERGE_PROGRAM\" > \"$_cw_stage\"; then\n    out_error 'failed to construct updated Claude settings.'\n    rm -f \"$_cw_stage\"\n    claude_rollback_settings\n    return 1\n  fi\n\n  if ! SETUP_API_KEY=\"$SETUP_API_KEY\" \"$JQ\" -e --arg baseUrl \"$SETUP_ENDPOINT\" '\n      (type == \"object\")\n      and ((.env | type) == \"object\")\n      and (.env.ANTHROPIC_BASE_URL == $baseUrl)\n      and (.env.ANTHROPIC_AUTH_TOKEN == env.SETUP_API_KEY)\n    ' \"$_cw_stage\" >/dev/null 2>&1; then\n    out_error 'staged Claude settings failed validation.'\n    rm -f \"$_cw_stage\"\n    claude_rollback_settings\n    return 1\n  fi\n\n  if ! chmod 600 \"$_cw_stage\"; then\n    rm -f \"$_cw_stage\"\n    claude_rollback_settings\n    return 1\n  fi\n\n  if ! mv \"$_cw_stage\" \"$CLAUDE_SETTINGS_PATH\"; then\n    out_error \"could not replace $CLAUDE_SETTINGS_PATH\"\n    rm -f \"$_cw_stage\"\n    claude_rollback_settings\n    return 1\n  fi\n  if ! _prune_managed_backups \"$CLAUDE_SETTINGS_PATH\" \"$CLAUDE_SETTINGS_BACKUP\"; then\n    claude_rollback_settings\n    return 1\n  fi\n}\n\nclaude_write_version() {\n  _cv_timeout=${AGENT_SETUP_TEST_TIMEOUT_SECONDS:-30}\n  _cv_version_file=\"$SETUP_TMPDIR/claude-version.out\"\n  if _run_with_timeout \"$_cv_timeout\" \"$CLAUDE_BIN\" --version > \"$_cv_version_file\" 2>&1; then\n    _cv_version=$(cat \"$_cv_version_file\")\n  else\n    _cv_version_status=$?\n    if [ \"$_cv_version_status\" -eq 124 ]; then\n      out_error '`claude --version` timed out.'\n    else\n      out_error '`claude --version` failed.'\n    fi\n    return 1\n  fi\n  out_info \"Claude Code version: $_cv_version\"\n}\n\n# Install, then configure Claude Code as one transactional settings write. A\n# freshly installed CLI is never uninstalled when configuration fails.\nconfigure_agent() {\n  out_agent_notice 'Installing' 'Claude Code'\n  if ! claude_ensure_installed; then\n    out_error 'Claude Code CLI is unavailable and could not be installed.'\n    return 1\n  fi\n  if ! claude_write_version; then\n    return 1\n  fi\n\n  out_agent_notice 'Configuring' 'Claude Code'\n  if ! ensure_jq; then\n    out_error 'jq is required to configure Claude Code but is unavailable and could not be provisioned for this platform. Install jq and re-run.'\n    return 1\n  fi\n  if ! claude_write_settings; then\n    return 1\n  fi\n  out_info \"Written to \\`$CLAUDE_SETTINGS_PATH\\`.\"\n  out_agent_notice 'Completed Agent Setup' 'Claude Code'\n}\n\n\nmain 'Claude Code' \"$@\"\n";

export const SETUP_BASH_CODEX = "# Codex Agent Setup fragment.\n\n# Track upstream's maintained installer so release-metadata fixes arrive without\n# waiting for a Floway update. Reviewed sources:\n# https://github.com/openai/codex/blob/d3fc1950a920f98e7fa9f11056667cdf911c38df/README.md#L18-L37\n# https://github.com/openai/codex/blob/d3fc1950a920f98e7fa9f11056667cdf911c38df/scripts/install/install.sh\ncodex_ensure_installed() {\n  _discover_cli codex \\\n    \"$HOME/.local/bin/codex\" \\\n    \"/opt/homebrew/bin/codex\" \\\n    \"/usr/local/bin/codex\"\n  CODEX_BIN=$DISCOVERED_BIN\n  if [ \"$DISCOVERED_COUNT\" -gt 1 ]; then\n    out_warn \"multiple Codex installations detected; using $CODEX_BIN\"\n  fi\n  if [ \"$DISCOVERED_COUNT\" -ge 1 ]; then\n    out_info 'Codex is already installed.'\n    return 0\n  fi\n\n  if [ -n \"${AGENT_SETUP_TEST_INSTALL_CODEX_SCRIPT:-}\" ]; then\n    out_info 'Codex CLI not found; running the test installer'\n    _icx_timeout=${AGENT_SETUP_TEST_TIMEOUT_SECONDS:-120}\n    _run_with_timeout \"$_icx_timeout\" env -u SETUP_API_KEY CODEX_NON_INTERACTIVE=true bash \"$AGENT_SETUP_TEST_INSTALL_CODEX_SCRIPT\" </dev/null || return 1\n  elif [ -n \"${AGENT_SETUP_TEST_CODEX_URL:-}\" ]; then\n    out_info 'Codex CLI not found; running the test installer download'\n    CODEX_NON_INTERACTIVE=true _download_and_run_installer \"$AGENT_SETUP_TEST_CODEX_URL\" || return 1\n  else\n    case \"$(uname -s)\" in\n      Darwin | Linux) ;;\n      *)\n        out_error 'automatic Codex installation supports macOS and Linux only in the Bash installer.'\n        return 1\n        ;;\n    esac\n    if [ \"$(uname -s)\" = Darwin ] && command -v brew >/dev/null 2>&1; then\n      out_info 'Codex CLI not found; installing with Homebrew'\n      _install_brew_cask codex || return 1\n    elif command -v npm >/dev/null 2>&1; then\n      out_info 'Codex CLI not found; installing with npm'\n      _install_npm_package '@openai/codex' || return 1\n    else\n      out_info 'Codex CLI not found; installing from GitHub'\n      CODEX_NON_INTERACTIVE=true _download_and_run_installer 'https://raw.githubusercontent.com/openai/codex/refs/heads/main/scripts/install/install.sh' || return 1\n    fi\n  fi\n  hash -r 2>/dev/null || true\n  _discover_cli codex \\\n    \"$HOME/.local/bin/codex\" \\\n    \"/opt/homebrew/bin/codex\" \\\n    \"/usr/local/bin/codex\"\n  CODEX_BIN=$DISCOVERED_BIN\n  [ \"$DISCOVERED_COUNT\" -ge 1 ]\n}\n\n# Back up the config and provider token before any mutation, recording the\n# absence of each so rollback can distinguish \"restore\" from \"remove\". The\n# token backup must be owner-only before the transaction can continue.\ncodex_backup_files() {\n  CODEX_CONFIG_EXISTED=0\n  CODEX_TOKEN_EXISTED=0\n  CODEX_CONFIG_BACKUP=\"\"\n  CODEX_TOKEN_BACKUP=\"\"\n  _cbf_stamp=$(date +%Y%m%d%H%M%S).$$\n  if [ -e \"$CODEX_CONFIG_PATH\" ]; then\n    CODEX_CONFIG_EXISTED=1\n    CODEX_CONFIG_BACKUP=\"$CODEX_CONFIG_PATH.floway-backup.$_cbf_stamp\"\n    if ! cp \"$CODEX_CONFIG_PATH\" \"$CODEX_CONFIG_BACKUP\"; then\n      out_error \"could not back up $CODEX_CONFIG_PATH\"\n      return 1\n    fi\n  fi\n  if [ -e \"$CODEX_TOKEN_PATH\" ]; then\n    CODEX_TOKEN_EXISTED=1\n    CODEX_TOKEN_BACKUP=\"$CODEX_TOKEN_PATH.floway-backup.$_cbf_stamp\"\n    if ! cp \"$CODEX_TOKEN_PATH\" \"$CODEX_TOKEN_BACKUP\"; then\n      out_error \"could not back up $CODEX_TOKEN_PATH\"\n      return 1\n    fi\n    if ! chmod 600 \"$CODEX_TOKEN_BACKUP\"; then\n      rm -f \"$CODEX_TOKEN_BACKUP\"\n      CODEX_TOKEN_BACKUP=\"\"\n      out_error \"could not protect the backup of $CODEX_TOKEN_PATH\"\n      return 1\n    fi\n  fi\n}\n\n# Both restores are attempted even when the first fails.\ncodex_rollback() {\n  _cxr_rc=0\n  _restore_managed_file \\\n    \"${CODEX_CONFIG_EXISTED:-0}\" \"${CODEX_CONFIG_BACKUP:-}\" \"$CODEX_CONFIG_PATH\" \\\n    \"file\" \"Codex config\" || _cxr_rc=1\n  _restore_managed_file \\\n    \"${CODEX_TOKEN_EXISTED:-0}\" \"${CODEX_TOKEN_BACKUP:-}\" \"$CODEX_TOKEN_PATH\" \\\n    \"provider token\" \"Codex provider token\" || _cxr_rc=1\n  return \"$_cxr_rc\"\n}\n\ncodex_commit_files() {\n  _prune_managed_backups \"$CODEX_CONFIG_PATH\" \"$CODEX_CONFIG_BACKUP\" || return 1\n  _prune_managed_backups \"$CODEX_TOKEN_PATH\" \"$CODEX_TOKEN_BACKUP\" || return 1\n  if [ -n \"$CODEX_TOKEN_BACKUP\" ] && ! rm -f \"$CODEX_TOKEN_BACKUP\"; then\n    out_error \"could not remove provider-token backup $CODEX_TOKEN_BACKUP\"\n    return 1\n  fi\n  CODEX_TOKEN_BACKUP=\"\"\n}\n\n# Terminate the app-server process group, giving a child whose stdin was just\n# closed a brief moment to exit on its own before escalating TERM then KILL. The\n# child is launched under job control so the whole descendant tree shares one\n# group. The natural-exit grace uses sub-second polling so a clean handshake\n# adds negligible latency.\n_codex_kill_group() {\n  _ckg_pid=$1\n  _ckg_n=0\n  while kill -0 \"$_ckg_pid\" 2>/dev/null && [ \"$_ckg_n\" -lt 5 ]; do\n    sleep 0.2\n    _ckg_n=$((_ckg_n + 1))\n  done\n  if kill -0 \"$_ckg_pid\" 2>/dev/null; then\n    kill -TERM -- \"-$_ckg_pid\" 2>/dev/null || kill -TERM \"$_ckg_pid\" 2>/dev/null || true\n    sleep 0.5\n    kill -KILL -- \"-$_ckg_pid\" 2>/dev/null || kill -KILL \"$_ckg_pid\" 2>/dev/null || true\n  fi\n  wait \"$_ckg_pid\" 2>/dev/null || true\n}\n\n# Read newline-delimited JSON-RPC from fd 4 until a response whose id matches\n# $1 arrives, demultiplexing unrelated notifications. Bounded by the absolute\n# CODEX_APPSERVER_DEADLINE. Returns 0 with the line in CODEX_APPSERVER_RESPONSE,\n# 124 on deadline, 1 on a premature stream EOF, 2 on a malformed (unparseable)\n# line, and 3 on a matching JSON-RPC error response.\n_codex_read_response() {\n  _crr_id=$1\n  while :; do\n    _crr_left=$(( CODEX_APPSERVER_DEADLINE - $(date +%s) ))\n    if [ \"$_crr_left\" -le 0 ]; then\n      return 124\n    fi\n    if IFS= read -r -t \"$_crr_left\" _crr_line <&4; then\n      [ -n \"$_crr_line\" ] || continue\n      _crr_kind=$(printf '%s\\n' \"$_crr_line\" | \"$JQ\" -r --argjson want \"$_crr_id\" '\n        if (.id == $want) then (if has(\"error\") then \"error\" elif has(\"result\") then \"result\" else \"pending\" end) else \"skip\" end\n      ' 2>/dev/null)\n      if [ -z \"$_crr_kind\" ]; then\n        return 2\n      fi\n      case \"$_crr_kind\" in\n        result) CODEX_APPSERVER_RESPONSE=$_crr_line; return 0 ;;\n        error) CODEX_APPSERVER_RESPONSE=$_crr_line; return 3 ;;\n        *) continue ;;\n      esac\n    else\n      _crr_rc=$?\n      if [ \"$_crr_rc\" -gt 128 ]; then\n        return 124\n      fi\n      return 1\n    fi\n  done\n}\n\n# Drive `codex app-server` over two private FIFOs: initialize -> initialized ->\n# config/batchWrite. stdin is kept open (fd 3) until the batch response arrives\n# on fd 4, so a server that answers after a delay still completes. The child\n# runs in its own process group for tree-wide termination; trap-invoked cleanup\n# removes the working directory. On success the raw batchWrite result JSON is the\n# only thing written to stdout (progress and errors go to stderr).\ncodex_app_server_batch_write() {\n  _cas_edits=$1\n  _cas_timeout=${AGENT_SETUP_TEST_TIMEOUT_SECONDS:-60}\n  _cas_dir=$(mktemp -d \"$SETUP_TMPDIR/codex-appserver.XXXXXX\") || return 1\n  _cas_req=\"$_cas_dir/req\"\n  _cas_res=\"$_cas_dir/res\"\n  if ! mkfifo \"$_cas_req\" \"$_cas_res\"; then\n    rm -rf \"$_cas_dir\"\n    return 1\n  fi\n\n  set -m\n  \"$CODEX_BIN\" app-server --listen stdio:// <\"$_cas_req\" >\"$_cas_res\" 2>\"$_cas_dir/stderr\" &\n  _cas_pid=$!\n  set +m\n\n  # Open the write end of req first (this unblocks the child's stdin open), then\n  # the read end of res. This ordering is what keeps a FIFO pair from deadlocking.\n  exec 3>\"$_cas_req\"\n  exec 4<\"$_cas_res\"\n\n  CODEX_APPSERVER_DEADLINE=$(( $(date +%s) + _cas_timeout ))\n  CODEX_APPSERVER_RESPONSE=\"\"\n  _cas_status=0\n\n  _cas_init=$(\"$JQ\" -cn '{jsonrpc:\"2.0\",id:1,method:\"initialize\",params:{clientInfo:{name:\"floway-setup\",title:null,version:\"1\"},capabilities:null}}')\n  printf '%s\\n' \"$_cas_init\" >&3 2>/dev/null || _cas_status=1\n  if [ \"$_cas_status\" -eq 0 ]; then\n    _codex_read_response 1\n    _cas_status=$?\n  fi\n  if [ \"$_cas_status\" -eq 0 ]; then\n    printf '%s\\n' '{\"jsonrpc\":\"2.0\",\"method\":\"initialized\"}' >&3 2>/dev/null || _cas_status=1\n  fi\n  if [ \"$_cas_status\" -eq 0 ]; then\n    _cas_batch=$(\"$JQ\" -cn --argjson edits \"$_cas_edits\" '{jsonrpc:\"2.0\",id:2,method:\"config/batchWrite\",params:{edits:$edits}}')\n    printf '%s\\n' \"$_cas_batch\" >&3 2>/dev/null || _cas_status=1\n  fi\n  _cas_result=\"\"\n  if [ \"$_cas_status\" -eq 0 ]; then\n    _codex_read_response 2\n    _cas_status=$?\n    _cas_result=$CODEX_APPSERVER_RESPONSE\n  fi\n\n  exec 3>&- 2>/dev/null || true\n  exec 4<&- 2>/dev/null || true\n  _codex_kill_group \"$_cas_pid\"\n  rm -rf \"$_cas_dir\"\n\n  if [ \"$_cas_status\" -ne 0 ]; then\n    return \"$_cas_status\"\n  fi\n  printf '%s' \"$_cas_result\"\n}\n\n# Build the base-config edit batch and write it through the app-server. Model\n# and effort are opaque, forwarded verbatim, and cleared with JSON null when\n# unset. A batch status of `ok` or `okOverridden` confirms the intended base\n# config; `okOverridden` is reported with its non-secret layer metadata.\ncodex_write_config() {\n  _cwc_base=\"${SETUP_ENDPOINT%/}/azure-api.codex\"\n  # Command auth opts a provider into online model refresh. The actor marker\n  # enables Codex's client-owned search and image extensions for this provider.\n  # https://github.com/openai/codex/blob/1bbdb32789e1f79932df44941236ea3658f6e965/codex-rs/models-manager/src/manager.rs#L413-L415\n  # https://github.com/openai/codex/blob/1bbdb32789e1f79932df44941236ea3658f6e965/codex-rs/model-provider-info/src/lib.rs#L396-L408\n  # standalone_web_search is under development, so its explicit opt-in is\n  # paired with the top-level warning suppression instead of warning every run.\n  # https://github.com/openai/codex/blob/24e9b849fad8f506971dfa0313dbdea8abd90112/codex-rs/features/src/lib.rs#L901-L905\n  # https://github.com/openai/codex/blob/24e9b849fad8f506971dfa0313dbdea8abd90112/codex-rs/features/src/lib.rs#L1393-L1439\n  _cwc_edits=$(\"$JQ\" -cn \\\n    --arg base \"$_cwc_base\" \\\n    --arg model \"$SETUP_CODEX_MODEL\" \\\n    --arg effort \"$SETUP_CODEX_REASONING_EFFORT\" '\n    [\n      {keyPath:\"model_provider\",mergeStrategy:\"replace\",value:\"floway\"},\n      {keyPath:\"suppress_unstable_features_warning\",mergeStrategy:\"replace\",value:true},\n      {keyPath:\"model_providers.floway.name\",mergeStrategy:\"replace\",value:\"Floway\"},\n      {keyPath:\"model_providers.floway.base_url\",mergeStrategy:\"replace\",value:$base},\n      {keyPath:\"model_providers.floway.auth\",mergeStrategy:\"replace\",value:{command:\"sh\",args:[\"-c\",\"cat \\\"${CODEX_HOME:-$HOME/.codex}/floway-token\\\"\"]}},\n      {keyPath:\"model_providers.floway.wire_api\",mergeStrategy:\"replace\",value:\"responses\"},\n      {keyPath:\"model_providers.floway.supports_websockets\",mergeStrategy:\"replace\",value:true},\n      {keyPath:\"model_providers.floway.http_headers\",mergeStrategy:\"replace\",value:{\"x-openai-actor-authorization\":\"1\"}},\n      {keyPath:\"features.apps\",mergeStrategy:\"replace\",value:false},\n      {keyPath:\"features.standalone_web_search\",mergeStrategy:\"replace\",value:true},\n      {keyPath:\"model\",mergeStrategy:\"replace\",value:(if $model == \"\" then null else $model end)},\n      {keyPath:\"model_reasoning_effort\",mergeStrategy:\"replace\",value:(if $effort == \"\" then null else $effort end)}\n    ]') || {\n    out_error 'could not build the Codex configuration edits.'\n    return 1\n  }\n\n  _cwc_result=$(codex_app_server_batch_write \"$_cwc_edits\")\n  _cwc_rc=$?\n  if [ \"$_cwc_rc\" -ne 0 ]; then\n    case \"$_cwc_rc\" in\n      124) out_error 'the Codex app-server timed out before confirming the configuration.' ;;\n      3) out_error 'the Codex app-server reported an error writing the configuration.' ;;\n      2) out_error 'the Codex app-server returned a malformed response.' ;;\n      1) out_error 'the Codex app-server exited before confirming the configuration.' ;;\n      *) out_error 'the Codex app-server configuration failed.' ;;\n    esac\n    return 1\n  fi\n\n  _cwc_status=$(printf '%s' \"$_cwc_result\" | \"$JQ\" -r '.result.status // empty' 2>/dev/null)\n  case \"$_cwc_status\" in\n    ok) ;;\n    okOverridden)\n      _cwc_msg=$(printf '%s' \"$_cwc_result\" | \"$JQ\" -r '.result.overriddenMetadata.message // \"an override layer applies\"' 2>/dev/null)\n      _cwc_layer=$(printf '%s' \"$_cwc_result\" | \"$JQ\" -r '.result.overriddenMetadata.overridingLayer.name.type // \"unknown\"' 2>/dev/null)\n      out_warn \"Codex configuration is overridden by a higher-precedence layer ($_cwc_msg; layer: $_cwc_layer).\"\n      ;;\n    *)\n      out_error \"the Codex app-server did not confirm the configuration (status: ${_cwc_status:-none}).\"\n      return 1\n      ;;\n  esac\n  CODEX_WRITTEN_CONFIG_PATH=$(printf '%s' \"$_cwc_result\" | \"$JQ\" -r '.result.filePath // empty' 2>/dev/null)\n  if [ -z \"$CODEX_WRITTEN_CONFIG_PATH\" ]; then\n    out_error 'the Codex app-server did not report the written config path.'\n    return 1\n  fi\n}\n\n# Store the selected API key as a provider-scoped command-auth token. The private\n# stage is validated byte-for-byte, then atomically renamed. auth.json is an\n# account-owned Codex file and is never read or changed here.\ncodex_stage_token() {\n  _cst_stage=\"$CODEX_TOKEN_PATH.floway-stage.$$\"\n  if ! (umask 077 && : > \"$_cst_stage\"); then\n    out_error 'could not create the Codex provider-token stage.'\n    return 1\n  fi\n  if ! printf '%s' \"$SETUP_API_KEY\" > \"$_cst_stage\"; then\n    out_error 'could not write the Codex provider-token stage.'\n    rm -f \"$_cst_stage\"\n    return 1\n  fi\n  if ! cmp -s \"$_cst_stage\" <(printf '%s' \"$SETUP_API_KEY\"); then\n    out_error 'staged Codex provider token failed validation.'\n    rm -f \"$_cst_stage\"\n    return 1\n  fi\n  if ! chmod 600 \"$_cst_stage\"; then\n    rm -f \"$_cst_stage\"\n    return 1\n  fi\n  if ! mv \"$_cst_stage\" \"$CODEX_TOKEN_PATH\"; then\n    out_error \"could not replace $CODEX_TOKEN_PATH\"\n    rm -f \"$_cst_stage\"\n    return 1\n  fi\n}\n\ncodex_write_version() {\n  _cv_timeout=${AGENT_SETUP_TEST_TIMEOUT_SECONDS:-30}\n  _cv_version_file=\"$SETUP_TMPDIR/codex-version.out\"\n  if _run_with_timeout \"$_cv_timeout\" \"$CODEX_BIN\" --version > \"$_cv_version_file\" 2>&1; then\n    out_info \"Codex version: $(cat \"$_cv_version_file\")\"\n  else\n    _cv_version_status=$?\n    if [ \"$_cv_version_status\" -eq 124 ]; then\n      out_error '`codex --version` timed out.'\n    else\n      out_error '`codex --version` failed.'\n    fi\n    return 1\n  fi\n}\n\n# Install, then configure Codex as one transactional config/token write. A\n# freshly installed CLI is never uninstalled when configuration fails.\nconfigure_agent() {\n  out_agent_notice 'Installing' 'Codex'\n  if ! codex_ensure_installed; then\n    out_error 'Codex CLI is unavailable and could not be installed.'\n    return 1\n  fi\n  if ! codex_write_version; then\n    return 1\n  fi\n\n  out_agent_notice 'Configuring' 'Codex'\n  if ! ensure_jq; then\n    out_error 'jq is required to configure Codex but is unavailable and could not be provisioned for this platform. Install jq and re-run.'\n    return 1\n  fi\n  CODEX_HOME_DIR=\"${CODEX_HOME:-$HOME/.codex}\"\n  CODEX_CONFIG_PATH=\"$CODEX_HOME_DIR/config.toml\"\n  CODEX_TOKEN_PATH=\"$CODEX_HOME_DIR/floway-token\"\n  if ! mkdir -p \"$CODEX_HOME_DIR\"; then\n    out_error \"could not create $CODEX_HOME_DIR\"\n    return 1\n  fi\n  if ! codex_backup_files; then\n    return 1\n  fi\n  if ! codex_stage_token; then\n    out_warn 'Codex provider-token staging failed; rolling back configuration and token.'\n    codex_rollback\n    return 1\n  fi\n  if ! codex_write_config; then\n    out_warn 'Codex configuration failed; rolling back configuration and token.'\n    codex_rollback\n    return 1\n  fi\n  if ! codex_commit_files; then\n    out_warn 'Codex backup cleanup failed; rolling back configuration and token.'\n    codex_rollback\n    return 1\n  fi\n  out_info \"Written to \\`$CODEX_WRITTEN_CONFIG_PATH\\`.\"\n  out_info \"Written to \\`$CODEX_TOKEN_PATH\\`.\"\n  out_agent_notice 'Completed Agent Setup' 'Codex'\n}\n\n\nmain 'Codex' \"$@\"\n";

export const SETUP_POWERSHELL_COMMON_OUTPUT = "# Floway Agent Setup common installer fragment (PowerShell). TypeScript prepends\n# the language-native assignment prefix and appends one agent fragment.\n#\n# Each served script targets exactly one agent and rolls back that agent's\n# configuration as one transaction on failure.\n\n# --- output layer -----------------------------------------------------------\n#\n# Setup-owned output follows Homebrew's compact visual language: blue `==>`\n# notices introduce major phases, while warnings and errors color only their\n# labels. Phase details remain subordinate instead of competing for attention.\n# Native package managers inherit the terminal directly, preserving their ANSI\n# colors, carriage-return progress, buffering, and cursor behavior.\n#\n# stdout color rides the host: `Write-Host -ForegroundColor` colors an\n# interactive console yet writes no escape sequences when redirected/captured,\n# so it is the correct stdout mechanism on both Windows PowerShell 5.1 and\n# PowerShell 7. stderr goes through [Console]::Error, colored with ANSI only for\n# an interactive error stream with NO_COLOR unset — a redirected capture stays\n# escape-free. UTF-8 output keeps the status glyphs portable to 5.1.\nfunction Write-SetupHostLine {\n  param([string]$Text, [System.ConsoleColor]$Color, [switch]$Plain)\n  if ($Plain -or $script:SetupNoColor) { Write-Host $Text } else { Write-Host $Text -ForegroundColor $Color }\n}\n\nfunction Write-SetupNotice {\n  param([string]$Text)\n  if ($script:SetupNoColor) { Write-Host \"==> $Text\"; return }\n  if ($script:SetupOutAnsi) {\n    Write-Host \"$($script:SetupEsc)[34m==>$($script:SetupEsc)[0m $($script:SetupEsc)[1m$Text$($script:SetupEsc)[0m\"\n    return\n  }\n  Write-Host '==>' -ForegroundColor Blue -NoNewline\n  Write-Host \" $Text\" -ForegroundColor White\n}\n\n# Console.Error is used directly so diagnostics remain on stderr while only the\n# Homebrew-style label receives color.\nfunction Write-SetupDiagnostic {\n  param([string]$Label, [string]$Text, [System.ConsoleColor]$Color, [string]$TestAnsiCode)\n  if ($script:SetupErrColor) {\n    $previous = [Console]::ForegroundColor\n    try {\n      [Console]::ForegroundColor = $Color\n      [Console]::Error.Write(\"${Label}:\")\n      [Console]::ForegroundColor = $previous\n      [Console]::Error.WriteLine(\" $Text\")\n    } finally {\n      [Console]::ForegroundColor = $previous\n    }\n  } elseif ($script:SetupForceColor -and (-not $script:SetupNoColor)) {\n    [Console]::Error.WriteLine(\"$($script:SetupEsc)[${TestAnsiCode}m${Label}:$($script:SetupEsc)[0m $Text\")\n  } else {\n    [Console]::Error.WriteLine(\"${Label}: $Text\")\n  }\n}\n\nfunction Write-SetupAgentNotice { param([string]$Label, [string]$AgentName) Write-SetupNotice \"${Label}: $AgentName\" }\nfunction Write-SetupMetadata { param([string]$Label, [string]$Value) Write-Host \"${Label}: $Value\" }\nfunction Write-SetupInfo { param([string]$Text) Write-SetupHostLine $Text -Plain }\nfunction Write-SetupWarn { param([string]$Text) Write-SetupDiagnostic 'Warning' $Text Yellow '93' }\nfunction Write-SetupError { param([string]$Text) Write-SetupDiagnostic 'Error' $Text Red '91' }\n\n# Report a primary error to stderr and unwind. The agent boundary recognizes the\n# 'setup-handled' marker as already reported, so no line is ever duplicated.\nfunction Stop-Setup { param([string]$Message) Write-SetupError $Message; throw 'setup-handled' }\n";

export const SETUP_POWERSHELL_COMMON_HELPERS = "# Windows PowerShell 5.1 only runs on Windows and has no $IsWindows automatic\n# variable; PowerShell 6+ exposes it on every platform.\nfunction Test-SetupIsWindows {\n  ($PSVersionTable.PSVersion.Major -lt 6) -or $IsWindows\n}\n\n# The AGENT_SETUP_TEST_TIMEOUT_SECONDS hook, read from the ambient environment\n# and never emitted by the gateway, lets the harness shorten every wall-clock\n# limit; otherwise the caller-supplied default applies.\nfunction Get-SetupTimeoutSeconds {\n  param([int]$Default)\n  if ($env:AGENT_SETUP_TEST_TIMEOUT_SECONDS) { [int]$env:AGENT_SETUP_TEST_TIMEOUT_SECONDS } else { $Default }\n}\n\nfunction Set-SetupProp {\n  param($Target, [string]$Name, $Value)\n  if ($Target.PSObject.Properties.Name -contains $Name) { $Target.$Name = $Value }\n  else { $Target | Add-Member -NotePropertyName $Name -NotePropertyValue $Value }\n}\n\nfunction Remove-SetupProp {\n  param($Target, [string]$Name)\n  if ($Target.PSObject.Properties.Name -contains $Name) { $Target.PSObject.Properties.Remove($Name) }\n}\n\n# A null optional value means \"remove this managed key\"; any other value is set.\nfunction Set-SetupOptionalProp {\n  param($Target, [string]$Name, $Value)\n  if ($null -eq $Value) { Remove-SetupProp $Target $Name } else { Set-SetupProp $Target $Name $Value }\n}\n\n# Redact every occurrence of the API key from text before it is surfaced.\nfunction Protect-SetupSecret {\n  param([string]$Text)\n  return ($Text -replace [regex]::Escape($SetupApiKey), '***')\n}\n\n# Restrict a file to the current user: chmod 0600 on Unix, an inheritance-free\n# owner-only ACL on Windows.\nfunction Protect-SetupFile {\n  param([string]$Path)\n  if (-not (Test-SetupIsWindows)) {\n    & chmod 600 $Path\n    if ($LASTEXITCODE -ne 0) { Stop-Setup \"could not restrict $Path to owner-only access.\" }\n    return\n  }\n  # Set-Acl routes through the PowerShell filesystem provider and may persist\n  # the untouched SACL, demanding SeSecurityPrivilege from a normal user. The\n  # direct .NET APIs write only this descriptor's modified DACL.\n  # https://github.com/PowerShell/PowerShell/blob/0c226762e2580cd7853c058dd03fc32638a73971/src/System.Management.Automation/namespaces/FileSystemSecurity.cs#L130-L200\n  # https://github.com/dotnet/runtime/blob/f94898a9b55df07348434e86915c7405962427b6/src/libraries/System.IO.FileSystem.AccessControl/src/System/Security/AccessControl/FileSystemSecurity.cs#L103-L125\n  $acl = New-Object System.Security.AccessControl.FileSecurity\n  $identity = [System.Security.Principal.WindowsIdentity]::GetCurrent().User\n  $rule = New-Object System.Security.AccessControl.FileSystemAccessRule($identity, 'FullControl', 'Allow')\n  $acl.SetAccessRuleProtection($true, $false)\n  $acl.AddAccessRule($rule)\n  if ($PSVersionTable.PSVersion.Major -lt 6) {\n    [System.IO.File]::SetAccessControl($Path, $acl)\n  } else {\n    [System.IO.FileSystemAclExtensions]::SetAccessControl([System.IO.FileInfo]::new($Path), $acl)\n  }\n}\n\n# Terminate a process and its descendants. PowerShell 7's runtime exposes the\n# tree-aware Kill(bool) overload; Windows PowerShell 5.1 uses taskkill /T.\nfunction Stop-SetupProcessTree {\n  param([System.Diagnostics.Process]$Process)\n  $runningOnWindows = Test-SetupIsWindows\n  if ($runningOnWindows) {\n    & taskkill.exe /PID $Process.Id /T /F *> $null\n    if ($LASTEXITCODE -ne 0 -and (-not $Process.HasExited)) {\n      Stop-Setup \"taskkill could not terminate process tree $($Process.Id).\"\n    }\n    return\n  }\n  try {\n    $Process.Kill($true)\n  } catch {\n    if (-not $Process.HasExited) { Stop-Setup \"could not terminate process tree $($Process.Id).\" }\n  }\n}\n\nfunction Get-SetupPlatform {\n  if (Test-SetupIsWindows) { return 'windows' }\n  if ($IsMacOS) { return 'macos' }\n  return 'linux'\n}\n\n# Run a fixed package-manager command with inherited stdout/stderr. The child\n# remains attached to the real terminal, so progress updates and ANSI control\n# sequences render in real time without a lossy line-prefix filter.\nfunction Invoke-SetupLiveProcess {\n  param([string]$Exe, [string[]]$Arguments, [int]$TimeoutSeconds)\n  $startInfo = New-Object System.Diagnostics.ProcessStartInfo\n  $startInfo.FileName = $Exe\n  $startInfo.Arguments = ($Arguments | ForEach-Object { '\"' + $_.Replace('\"', '\\\"') + '\"' }) -join ' '\n  $startInfo.UseShellExecute = $false\n  $startInfo.CreateNoWindow = $false\n  $process = New-Object System.Diagnostics.Process\n  $process.StartInfo = $startInfo\n  if (-not $process.Start()) { Stop-Setup \"failed to start $Exe.\" }\n  if (-not $process.WaitForExit($TimeoutSeconds * 1000)) {\n    Stop-SetupProcessTree $process\n    $process.WaitForExit()\n    Stop-Setup \"$Exe timed out after $TimeoutSeconds seconds.\"\n  }\n  if ($process.ExitCode -ne 0) { Stop-Setup \"$Exe exited with status $($process.ExitCode).\" }\n}\n\nfunction Install-SetupHomebrewCask {\n  param([string]$Cask)\n  $brew = Get-Command brew -CommandType Application -ErrorAction SilentlyContinue | Select-Object -First 1\n  if (-not $brew) { Stop-Setup 'Homebrew is required to install agent CLIs on macOS.' }\n  $timeoutSeconds = Get-SetupTimeoutSeconds 600\n  Invoke-SetupLiveProcess -Exe $brew.Source -Arguments @('install', '--cask', $Cask) -TimeoutSeconds $timeoutSeconds\n}\n\n# npm on Windows is commonly a .cmd launcher, which ProcessStartInfo cannot\n# execute directly with UseShellExecute disabled. A fresh copy of the current\n# PowerShell host resolves that launcher while preserving inherited terminal\n# output and the same process-tree timeout.\nfunction Install-SetupNpmPackage {\n  param([string]$Package)\n  $npm = Get-Command npm -CommandType Application -ErrorAction SilentlyContinue | Select-Object -First 1\n  if (-not $npm) { Stop-Setup 'npm was selected for installation but is no longer available.' }\n  $hostCommand = Get-Command pwsh -CommandType Application -ErrorAction SilentlyContinue | Select-Object -First 1\n  $hostExe = if ($hostCommand) { $hostCommand.Source } else { [System.Diagnostics.Process]::GetCurrentProcess().MainModule.FileName }\n  $npmLiteral = \"'\" + $npm.Source.Replace(\"'\", \"''\") + \"'\"\n  $packageLiteral = \"'\" + $Package.Replace(\"'\", \"''\") + \"'\"\n  $command = \"& $npmLiteral install --global $packageLiteral; exit `$LASTEXITCODE\"\n  $timeoutSeconds = Get-SetupTimeoutSeconds 600\n  Invoke-SetupLiveProcess -Exe $hostExe -Arguments @('-NoProfile', '-NonInteractive', '-Command', $command) -TimeoutSeconds $timeoutSeconds\n}\n\n# Execute a downloaded installer in a fresh interpreter. The script travels\n# through stdin, while the API key exists only as a variable in this parent\n# process and its identically named environment variables were removed. The\n# official installer therefore cannot read the credential.\nfunction Invoke-SetupInterpreterBody {\n  param([string]$Body, [int]$TimeoutSeconds, [string]$Exe, [string]$Arguments)\n  $startInfo = New-Object System.Diagnostics.ProcessStartInfo\n  $startInfo.FileName = $Exe\n  $startInfo.Arguments = $Arguments\n  $startInfo.UseShellExecute = $false\n  $startInfo.CreateNoWindow = $false\n  $startInfo.RedirectStandardInput = $true\n  $process = New-Object System.Diagnostics.Process\n  $process.StartInfo = $startInfo\n  if (-not $process.Start()) { Stop-Setup \"failed to start the installer interpreter.\" }\n  $process.StandardInput.Write($Body)\n  $process.StandardInput.WriteLine()\n  $process.StandardInput.Close()\n  if (-not $process.WaitForExit($TimeoutSeconds * 1000)) {\n    Stop-SetupProcessTree $process\n    $process.WaitForExit()\n    Stop-Setup \"the installer timed out after $TimeoutSeconds seconds.\"\n  }\n  if ($process.ExitCode -ne 0) { Stop-Setup \"the installer exited with status $($process.ExitCode).\" }\n}\n\nfunction Invoke-SetupPowerShellBody {\n  param([string]$Body, [int]$TimeoutSeconds, [switch]$BypassExecutionPolicy)\n  $pwsh = Get-Command pwsh -CommandType Application -ErrorAction SilentlyContinue | Select-Object -First 1\n  $exe = if ($pwsh) { $pwsh.Source } else { [System.Diagnostics.Process]::GetCurrentProcess().MainModule.FileName }\n  $executionPolicy = if ($BypassExecutionPolicy) { '-ExecutionPolicy Bypass ' } else { '' }\n  Invoke-SetupInterpreterBody -Body $Body -TimeoutSeconds $TimeoutSeconds -Exe $exe -Arguments \"-NoProfile -NonInteractive ${executionPolicy}-Command -\"\n}\n\nfunction Invoke-SetupShellBody {\n  param([string]$Body, [int]$TimeoutSeconds)\n  $bash = Get-Command bash -CommandType Application -ErrorAction SilentlyContinue | Select-Object -First 1\n  if (-not $bash) { Stop-Setup 'bash is required to run the official installer on macOS and Linux.' }\n  Invoke-SetupInterpreterBody -Body $Body -TimeoutSeconds $TimeoutSeconds -Exe $bash.Source -Arguments '-s'\n}\n\n# Download an installer, refuse anything that is not a script (region blocks and\n# captive portals serve HTML in place of the installer), then run it.\nfunction Invoke-SetupRemoteInstaller {\n  param([string]$Uri, [switch]$BypassExecutionPolicy, [switch]$Shell)\n  $response = Invoke-WebRequest -Uri $Uri -UseBasicParsing -TimeoutSec 60\n  $body = [string]$response.Content\n  $contentType = [string]$response.Headers['Content-Type']\n  $looksLikeHtml = $contentType -match '(?i)^text/html(?:;|$)' -or $body -match '(?is)^\\s*(?:<!doctype\\s+html|<html(?:\\s|>))'\n  if ([string]::IsNullOrWhiteSpace($body) -or $looksLikeHtml) {\n    Stop-Setup \"the installer download was HTML or empty, not an executable script (a login or region-block page?).\"\n  }\n  $timeoutSeconds = Get-SetupTimeoutSeconds 120\n  if ($Shell) { Invoke-SetupShellBody -Body $body -TimeoutSeconds $timeoutSeconds }\n  else { Invoke-SetupPowerShellBody -Body $body -TimeoutSeconds $timeoutSeconds -BypassExecutionPolicy:$BypassExecutionPolicy }\n}\n\nfunction Get-SetupCliExe {\n  param([string]$Name, [string]$Label, [string[]]$Candidates)\n  $found = New-Object System.Collections.Generic.List[string]\n  $command = Get-Command $Name -CommandType Application -ErrorAction SilentlyContinue | Select-Object -First 1\n  if ($command) { $found.Add($command.Source) }\n  foreach ($candidate in $Candidates) {\n    if ((Test-Path -LiteralPath $candidate) -and (-not $found.Contains($candidate))) { $found.Add($candidate) }\n  }\n  if ($found.Count -eq 0) { return $null }\n  if ($found.Count -gt 1) { Write-SetupWarn \"multiple $Label installations detected; using $($found[0])\" }\n  return $found[0]\n}\n\n# Rollback retains a backup when restoration fails so manual recovery remains\n# possible, warning with the preserved path and the action to take — matching\n# the Bash installer. The AGENT_SETUP_TEST_FAIL_RESTORE hook, read from the\n# ambient environment and never emitted by the gateway, forces the restore\n# rename to fail so the harness can assert that guidance.\nfunction Restore-SetupManagedFile {\n  param([bool]$Existed, [string]$Backup, [string]$Path, [string]$OriginalLabel, [string]$CreatedLabel)\n  if ($Existed) {\n    if ($Backup -and (Test-Path -LiteralPath $Backup)) {\n      try {\n        if ($env:AGENT_SETUP_TEST_FAIL_RESTORE) { throw 'test-injected restore failure' }\n        # Secret-bearing backups were already owner-only before any mutation.\n        # Moving one back preserves that protection without a second operation\n        # that could fail after the backup path has been consumed.\n        Move-Item -LiteralPath $Backup -Destination $Path -Force\n      } catch {\n        Write-SetupWarn \"could not restore $Path from its backup; your original $OriginalLabel is preserved at $Backup — restore it by hand.\"\n      }\n    }\n  } elseif (Test-Path -LiteralPath $Path) {\n    try {\n      Remove-Item -LiteralPath $Path -Force\n    } catch {\n      Write-SetupWarn \"could not remove the $CreatedLabel this run created at $Path — remove it by hand.\"\n    }\n  }\n}\n\nfunction Remove-SetupOlderBackups {\n  param([string]$Path, [string]$Keep)\n  $directory = Split-Path -Parent $Path\n  $prefix = [System.IO.Path]::GetFileName($Path) + '.floway-backup.'\n  Get-ChildItem -LiteralPath $directory -File -ErrorAction Stop |\n    Where-Object { $_.Name.StartsWith($prefix, [System.StringComparison]::Ordinal) -and $_.FullName -ne $Keep } |\n    Remove-Item -Force -ErrorAction Stop\n}\n\n# Run a child process with captured output under a deadline, terminating its\n# whole process tree and throwing on timeout.\nfunction Invoke-SetupProcess {\n  param([string]$Exe, [string[]]$Arguments, [int]$TimeoutSeconds, [string]$TimeoutMessage)\n  $startInfo = New-Object System.Diagnostics.ProcessStartInfo\n  $startInfo.FileName = $Exe\n  $startInfo.UseShellExecute = $false\n  $startInfo.CreateNoWindow = $true\n  $startInfo.RedirectStandardOutput = $true\n  $startInfo.RedirectStandardError = $true\n  # ArgumentList is unavailable in Windows PowerShell 5.1. These arguments are\n  # fixed internal tokens, so quoting them with ProcessStartInfo.Arguments is\n  # safe and keeps external input out of the child command line.\n  $startInfo.Arguments = ($Arguments | ForEach-Object { '\"' + $_.Replace('\"', '\\\"') + '\"' }) -join ' '\n  $process = New-Object System.Diagnostics.Process\n  $process.StartInfo = $startInfo\n  if (-not $process.Start()) { Stop-Setup \"failed to start $Exe.\" }\n  $stdoutTask = $process.StandardOutput.ReadToEndAsync()\n  $stderrTask = $process.StandardError.ReadToEndAsync()\n  if (-not $process.WaitForExit($TimeoutSeconds * 1000)) {\n    Stop-SetupProcessTree $process\n    $process.WaitForExit()\n    Stop-Setup $(if ($TimeoutMessage) { $TimeoutMessage } else { \"$Exe timed out after $TimeoutSeconds seconds.\" })\n  }\n  $stdout = $stdoutTask.GetAwaiter().GetResult()\n  $stderr = $stderrTask.GetAwaiter().GetResult()\n  [PSCustomObject]@{ ExitCode = $process.ExitCode; Output = ($stdout + $stderr) }\n}\n";

export const SETUP_POWERSHELL_COMMON_MAIN = "# --- run --------------------------------------------------------------------\n\nfunction Main {\n  param([string]$AgentName)\n  $ErrorActionPreference = 'Stop'\n  # Keep native command failures from auto-throwing on PowerShell 7.3+ so the\n  # explicit exit-code checks remain authoritative across versions.\n  $PSNativeCommandUseErrorActionPreference = $false\n\n  Remove-Item Env:SETUP_API_KEY -ErrorAction SilentlyContinue\n\n  try { [Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false) } catch { }\n  $script:SetupNoColor = [bool]$env:NO_COLOR\n  $script:SetupForceColor = [bool]$env:AGENT_SETUP_TEST_FORCE_COLOR\n  $script:SetupErrColor = (-not [Console]::IsErrorRedirected) -and (-not $script:SetupNoColor)\n  $script:SetupEsc = [char]27\n  $supportsVt = try { [bool]$Host.UI.SupportsVirtualTerminal } catch { $false }\n  $script:SetupOutAnsi = $supportsVt -and (-not [Console]::IsOutputRedirected) -and (-not $script:SetupNoColor)\n\n  Write-SetupAgentNotice 'Agent Setup' $AgentName\n  if ([string]::IsNullOrWhiteSpace($SetupEndpoint)) {\n    Write-SetupError \"`$SetupEndpoint must be set to this gateway origin (e.g. https://gateway.example).\"\n    return 1\n  }\n  if ($SetupEndpoint -notmatch '^https?://.+') {\n    Write-SetupError \"`$SetupEndpoint must be an http(s) origin, got $SetupEndpoint\"\n    return 1\n  }\n  Write-SetupMetadata 'Endpoint' $SetupEndpoint\n  Write-SetupMetadata 'API Key' $SetupApiKeyName\n\n  # Detection sites rethrow reported failures as the `setup-handled` sentinel;\n  # only unexpected exceptions are reported again here after redaction.\n  try {\n    Set-SetupAgent\n  } catch {\n    if ($_.Exception.Message -ne 'setup-handled') { Write-SetupError (Protect-SetupSecret ([string]$_.Exception.Message)) }\n    return 1\n  }\n  return 0\n}\n";

export const SETUP_POWERSHELL_CLAUDE = "# Claude Code Agent Setup fragment.\n\n# Install the official Claude Code package. The\n# AGENT_SETUP_TEST_INSTALL_CLAUDE_SCRIPT hook — read from the ambient\n# environment, never emitted by the gateway — substitutes a fake installer\n# under test.\nfunction Install-SetupClaude {\n  if ($env:AGENT_SETUP_TEST_INSTALL_CLAUDE_SCRIPT) {\n    Write-SetupInfo 'Claude Code CLI not found; running the test installer'\n    $timeoutSeconds = Get-SetupTimeoutSeconds 120\n    $installer = Invoke-SetupProcess -Exe $env:AGENT_SETUP_TEST_INSTALL_CLAUDE_SCRIPT -Arguments @() -TimeoutSeconds $timeoutSeconds\n    if ($installer.ExitCode -ne 0) { Stop-Setup \"the test installer hook failed.\" }\n    return\n  }\n  if ($env:AGENT_SETUP_TEST_CLAUDE_URL) {\n    Write-SetupInfo 'Claude Code CLI not found; running the test installer download'\n    Invoke-SetupRemoteInstaller -Uri $env:AGENT_SETUP_TEST_CLAUDE_URL\n    return\n  }\n  $platform = Get-SetupPlatform\n  $npm = Get-Command npm -CommandType Application -ErrorAction SilentlyContinue | Select-Object -First 1\n  switch ($platform) {\n    'macos' {\n      $brew = Get-Command brew -CommandType Application -ErrorAction SilentlyContinue | Select-Object -First 1\n      if ($brew) {\n        Write-SetupInfo 'Claude Code CLI not found; installing with Homebrew'\n        Install-SetupHomebrewCask -Cask 'claude-code'\n      } elseif ($npm) {\n        Write-SetupInfo 'Claude Code CLI not found; installing with npm'\n        Install-SetupNpmPackage -Package '@anthropic-ai/claude-code'\n      } else {\n        # Ref: https://code.claude.com/docs/en/setup\n        Write-SetupInfo 'Claude Code CLI not found; installing from downloads.claude.ai'\n        Invoke-SetupRemoteInstaller -Uri 'https://downloads.claude.ai/claude-code-releases/bootstrap.sh' -Shell\n      }\n    }\n    'windows' {\n      if ($npm) {\n        Write-SetupInfo 'Claude Code CLI not found; installing with npm'\n        Install-SetupNpmPackage -Package '@anthropic-ai/claude-code'\n      } else {\n        # Ref: https://code.claude.com/docs/en/setup\n        Write-SetupInfo 'Claude Code CLI not found; installing from downloads.claude.ai'\n        Invoke-SetupRemoteInstaller -Uri 'https://downloads.claude.ai/claude-code-releases/bootstrap.ps1'\n      }\n    }\n    'linux' {\n      if ($npm) {\n        Write-SetupInfo 'Claude Code CLI not found; installing with npm'\n        Install-SetupNpmPackage -Package '@anthropic-ai/claude-code'\n      } else {\n        # Ref: https://code.claude.com/docs/en/setup\n        Write-SetupInfo 'Claude Code CLI not found; installing from downloads.claude.ai'\n        Invoke-SetupRemoteInstaller -Uri 'https://downloads.claude.ai/claude-code-releases/bootstrap.sh' -Shell\n      }\n    }\n  }\n}\n\n# Surgically merge the managed keys into the Claude settings file: validate the\n# existing document, back it up, construct and validate the replacement in the\n# same directory, then atomically rename it into place with owner-only access.\nfunction Write-SetupClaudeSettings {\n  $configDir = if ($env:CLAUDE_CONFIG_DIR) { $env:CLAUDE_CONFIG_DIR } else { Join-Path $HOME '.claude' }\n  $script:ClaudeSettingsPath = Join-Path $configDir 'settings.json'\n  $script:ClaudeSettingsBackup = $null\n  $script:ClaudeSettingsExisted = $false\n  if (-not (Test-Path -LiteralPath $configDir)) {\n    New-Item -ItemType Directory -Path $configDir -Force | Out-Null\n  }\n\n  if (Test-Path -LiteralPath $script:ClaudeSettingsPath) {\n    $script:ClaudeSettingsExisted = $true\n    $raw = Get-Content -Raw -LiteralPath $script:ClaudeSettingsPath\n    try { $document = $raw | ConvertFrom-Json } catch { Stop-Setup \"$($script:ClaudeSettingsPath) is not valid JSON; leaving it untouched.\" }\n    if ($document -isnot [System.Management.Automation.PSCustomObject]) { Stop-Setup \"existing Claude settings root is not a JSON object.\" }\n    if (($document.PSObject.Properties.Name -contains 'env') -and ($document.env -isnot [System.Management.Automation.PSCustomObject])) {\n      Stop-Setup \"existing Claude settings env is not a JSON object.\"\n    }\n    if (($document.PSObject.Properties.Name -contains 'attribution') -and ($document.attribution -isnot [System.Management.Automation.PSCustomObject])) {\n      Stop-Setup \"existing Claude settings attribution is not a JSON object.\"\n    }\n    # DateTimeOffset.ToUnixTimeMilliseconds is unavailable on the .NET\n    # Framework version bundled with the Windows PowerShell 5.1 baseline.\n    $stamp = [long]([DateTimeOffset]::UtcNow - [DateTimeOffset]'1970-01-01T00:00:00Z').TotalMilliseconds\n    $script:ClaudeSettingsBackup = \"$($script:ClaudeSettingsPath).floway-backup.$stamp.$PID\"\n    try {\n      Copy-Item -LiteralPath $script:ClaudeSettingsPath -Destination $script:ClaudeSettingsBackup\n      Protect-SetupFile $script:ClaudeSettingsBackup\n    } catch {\n      if (Test-Path -LiteralPath $script:ClaudeSettingsBackup) {\n        Remove-Item -LiteralPath $script:ClaudeSettingsBackup -Force\n      }\n      $script:ClaudeSettingsBackup = $null\n      throw\n    }\n  } else {\n    $document = [PSCustomObject]@{}\n  }\n\n  if ($document.PSObject.Properties.Name -notcontains 'env') {\n    $document | Add-Member -NotePropertyName env -NotePropertyValue ([PSCustomObject]@{})\n  }\n  # Refs: https://docs.claude.com/en/docs/claude-code/env-vars\n  #       https://docs.claude.com/en/docs/claude-code/model-config#environment-variables\n  #       https://docs.claude.com/en/docs/claude-code/settings\n  #       https://code.claude.com/docs/en/settings#attribution-settings\n  Set-SetupProp $document.env 'ANTHROPIC_BASE_URL' $SetupEndpoint\n  Set-SetupProp $document.env 'ANTHROPIC_AUTH_TOKEN' $SetupApiKey\n  Set-SetupOptionalProp $document.env 'ANTHROPIC_MODEL' $SetupClaudeModel\n  Set-SetupOptionalProp $document.env 'ANTHROPIC_DEFAULT_OPUS_MODEL' $SetupClaudeDefaultOpusModel\n  Set-SetupOptionalProp $document.env 'ANTHROPIC_DEFAULT_SONNET_MODEL' $SetupClaudeDefaultSonnetModel\n  Set-SetupOptionalProp $document.env 'ANTHROPIC_DEFAULT_HAIKU_MODEL' $SetupClaudeDefaultHaikuModel\n  if ($SetupClaudeModelDiscovery) { Set-SetupProp $document.env 'CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY' '1' }\n  else { Remove-SetupProp $document.env 'CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY' }\n  Set-SetupOptionalProp $document 'effortLevel' $SetupClaudeEffortLevel\n  Set-SetupOptionalProp $document 'cleanupPeriodDays' $SetupClaudeCleanupPeriodDays\n  if ($SetupClaudeOptOutAiAttribution) {\n    if ($document.PSObject.Properties.Name -notcontains 'attribution') {\n      $document | Add-Member -NotePropertyName attribution -NotePropertyValue ([PSCustomObject]@{})\n    }\n    Set-SetupProp $document.attribution 'commit' ''\n    Set-SetupProp $document.attribution 'pr' ''\n    Set-SetupProp $document.attribution 'sessionUrl' $false\n  } elseif ($document.PSObject.Properties.Name -contains 'attribution') {\n    Remove-SetupProp $document.attribution 'commit'\n    Remove-SetupProp $document.attribution 'pr'\n    Remove-SetupProp $document.attribution 'sessionUrl'\n    if ($document.attribution.PSObject.Properties.Count -eq 0) { Remove-SetupProp $document 'attribution' }\n  }\n\n  $stage = \"$($script:ClaudeSettingsPath).floway-stage.$PID\"\n  try {\n    # The stage exists and is owner-only before any secret JSON is written.\n    [System.IO.File]::Create($stage).Dispose()\n    Protect-SetupFile $stage\n    $json = $document | ConvertTo-Json -Depth 100\n    # Write UTF-8 without a BOM on every PowerShell version so downstream JSON\n    # parsers accept the file.\n    [System.IO.File]::WriteAllText($stage, $json, (New-Object System.Text.UTF8Encoding($false)))\n    $check = Get-Content -Raw -LiteralPath $stage | ConvertFrom-Json\n    if (($check.env.ANTHROPIC_BASE_URL -cne $SetupEndpoint) -or ($check.env.ANTHROPIC_AUTH_TOKEN -cne $SetupApiKey)) {\n      Stop-Setup \"staged Claude settings failed validation.\"\n    }\n    $runningOnWindows = Test-SetupIsWindows\n    if ($script:ClaudeSettingsExisted -and $runningOnWindows) {\n      # File.Replace preserves the destination ACL, so tighten it first rather\n      # than letting a permissive historical DACL survive the atomic replace.\n      Protect-SetupFile $script:ClaudeSettingsPath\n      # PowerShell binds ordinary $null to String.Empty for a .NET string\n      # parameter; NullString passes an actual null backup path.\n      # https://learn.microsoft.com/en-us/dotnet/api/system.management.automation.language.nullstring\n      [System.IO.File]::Replace($stage, $script:ClaudeSettingsPath, [System.Management.Automation.Language.NullString]::Value)\n    } else {\n      # Move-Item is an atomic same-filesystem rename on Unix and creates a new\n      # target on Windows. Windows replacing an existing target uses File.Replace.\n      Move-Item -LiteralPath $stage -Destination $script:ClaudeSettingsPath -Force\n    }\n    Remove-SetupOlderBackups -Path $script:ClaudeSettingsPath -Keep $script:ClaudeSettingsBackup\n  } catch {\n    if (Test-Path -LiteralPath $stage) { Remove-Item -LiteralPath $stage -Force }\n    Restore-SetupManagedFile -Existed $script:ClaudeSettingsExisted -Backup $script:ClaudeSettingsBackup -Path $script:ClaudeSettingsPath -OriginalLabel 'file' -CreatedLabel 'Claude settings'\n    throw\n  }\n}\n\nfunction Write-SetupClaudeVersion {\n  param([string]$Exe)\n  $timeoutSeconds = Get-SetupTimeoutSeconds 30\n  $version = Invoke-SetupProcess -Exe $Exe -Arguments @('--version') -TimeoutSeconds $timeoutSeconds -TimeoutMessage '``claude --version`` timed out.'\n  if ($version.ExitCode -ne 0) { Stop-Setup \"``claude --version`` failed.\" }\n  Write-SetupInfo \"Claude Code version: $($version.Output.Trim())\"\n}\n\n# Install, then configure Claude Code as one transactional settings write. A\n# freshly installed CLI is never uninstalled when configuration fails.\nfunction Set-SetupAgent {\n  Write-SetupAgentNotice 'Installing' 'Claude Code'\n  # Ref: https://docs.claude.com/en/docs/claude-code/troubleshoot-install\n  $candidates = @(\n    (Join-Path $HOME '.local/bin/claude'),\n    (Join-Path $HOME '.local/bin/claude.exe'),\n    (Join-Path $HOME '.claude/local/claude')\n  )\n  if ($env:USERPROFILE) { $candidates += (Join-Path $env:USERPROFILE '.local\\bin\\claude.exe') }\n  $exe = Get-SetupCliExe -Name claude -Label 'Claude Code' -Candidates $candidates\n  if (-not $exe) {\n    Install-SetupClaude\n    $exe = Get-SetupCliExe -Name claude -Label 'Claude Code' -Candidates $candidates\n    if (-not $exe) { Stop-Setup \"Claude Code CLI is unavailable and could not be installed.\" }\n  } else {\n    Write-SetupInfo 'Claude Code is already installed.'\n  }\n  Write-SetupClaudeVersion -Exe $exe\n\n  Write-SetupAgentNotice 'Configuring' 'Claude Code'\n  Write-SetupClaudeSettings\n  Write-SetupInfo ('Written to `' + $script:ClaudeSettingsPath + '`.')\n  Write-SetupAgentNotice 'Completed Agent Setup' 'Claude Code'\n}\n\n\n$global:LASTEXITCODE = Main 'Claude Code'\n";

export const SETUP_POWERSHELL_CODEX = "# Codex Agent Setup fragment.\n\n# Install the official Codex package. CODEX_NON_INTERACTIVE keeps the direct\n# installer from prompting. We track upstream's maintained scripts so release-\n# metadata fixes arrive without waiting for a Floway update. Reviewed sources:\n# https://github.com/openai/codex/blob/d3fc1950a920f98e7fa9f11056667cdf911c38df/README.md#L18-L37\n# https://github.com/openai/codex/blob/d3fc1950a920f98e7fa9f11056667cdf911c38df/scripts/install/install.sh\n# https://github.com/openai/codex/blob/d3fc1950a920f98e7fa9f11056667cdf911c38df/scripts/install/install.ps1\n# The AGENT_SETUP_TEST_INSTALL_CODEX_SCRIPT hook —\n# read from the ambient environment, never emitted by the gateway — substitutes\n# a fake installer under test.\nfunction Install-SetupCodex {\n  $hadNonInteractive = Test-Path Env:CODEX_NON_INTERACTIVE\n  $previousNonInteractive = $env:CODEX_NON_INTERACTIVE\n  try {\n    $env:CODEX_NON_INTERACTIVE = 'true'\n    if ($env:AGENT_SETUP_TEST_INSTALL_CODEX_SCRIPT) {\n      Write-SetupInfo 'Codex CLI not found; running the test installer'\n      $timeoutSeconds = Get-SetupTimeoutSeconds 120\n      $installer = Invoke-SetupProcess -Exe $env:AGENT_SETUP_TEST_INSTALL_CODEX_SCRIPT -Arguments @() -TimeoutSeconds $timeoutSeconds\n      if ($installer.ExitCode -ne 0) { Stop-Setup \"the test codex installer hook failed.\" }\n      return\n    }\n    if ($env:AGENT_SETUP_TEST_CODEX_URL) {\n      Write-SetupInfo 'Codex CLI not found; running the test installer download'\n      Invoke-SetupRemoteInstaller -Uri $env:AGENT_SETUP_TEST_CODEX_URL -BypassExecutionPolicy\n      return\n    }\n    $platform = Get-SetupPlatform\n    $npm = Get-Command npm -CommandType Application -ErrorAction SilentlyContinue | Select-Object -First 1\n    $brew = if ($platform -eq 'macos') { Get-Command brew -CommandType Application -ErrorAction SilentlyContinue | Select-Object -First 1 } else { $null }\n    if ($brew) {\n      Write-SetupInfo 'Codex CLI not found; installing with Homebrew'\n      Install-SetupHomebrewCask -Cask 'codex'\n    } elseif ($npm) {\n      Write-SetupInfo 'Codex CLI not found; installing with npm'\n      Install-SetupNpmPackage -Package '@openai/codex'\n    } elseif ($platform -eq 'windows') {\n      Write-SetupInfo 'Codex CLI not found; installing from GitHub'\n      Invoke-SetupRemoteInstaller -Uri 'https://raw.githubusercontent.com/openai/codex/refs/heads/main/scripts/install/install.ps1'\n    } else {\n      Write-SetupInfo 'Codex CLI not found; installing from GitHub'\n      Invoke-SetupRemoteInstaller -Uri 'https://raw.githubusercontent.com/openai/codex/refs/heads/main/scripts/install/install.sh' -Shell\n    }\n  } finally {\n    if ($hadNonInteractive) { $env:CODEX_NON_INTERACTIVE = $previousNonInteractive }\n    else { Remove-Item Env:CODEX_NON_INTERACTIVE -ErrorAction SilentlyContinue }\n  }\n}\n\n# Back up the config and provider token before any mutation, recording the\n# absence of each so rollback can distinguish \"restore\" from \"remove\".\nfunction Backup-SetupCodexFiles {\n  $script:CodexConfigExisted = $false\n  $script:CodexTokenExisted = $false\n  $script:CodexConfigBackup = $null\n  $script:CodexTokenBackup = $null\n  # DateTimeOffset.ToUnixTimeMilliseconds is unavailable on the .NET Framework\n  # version bundled with the Windows PowerShell 5.1 baseline.\n  $stamp = [long]([DateTimeOffset]::UtcNow - [DateTimeOffset]'1970-01-01T00:00:00Z').TotalMilliseconds\n  if (Test-Path -LiteralPath $script:CodexConfigPath) {\n    $script:CodexConfigExisted = $true\n    $script:CodexConfigBackup = \"$($script:CodexConfigPath).floway-backup.$stamp.$PID\"\n    Copy-Item -LiteralPath $script:CodexConfigPath -Destination $script:CodexConfigBackup\n  }\n  if (Test-Path -LiteralPath $script:CodexTokenPath) {\n    $script:CodexTokenExisted = $true\n    $script:CodexTokenBackup = \"$($script:CodexTokenPath).floway-backup.$stamp.$PID\"\n    try {\n      Copy-Item -LiteralPath $script:CodexTokenPath -Destination $script:CodexTokenBackup\n      Protect-SetupFile $script:CodexTokenBackup\n    } catch {\n      if (Test-Path -LiteralPath $script:CodexTokenBackup) {\n        Remove-Item -LiteralPath $script:CodexTokenBackup -Force\n      }\n      $script:CodexTokenBackup = $null\n      throw\n    }\n  }\n}\n\nfunction Restore-SetupCodexFiles {\n  Restore-SetupManagedFile -Existed $script:CodexConfigExisted -Backup $script:CodexConfigBackup -Path $script:CodexConfigPath -OriginalLabel 'file' -CreatedLabel 'Codex config'\n  Restore-SetupManagedFile -Existed $script:CodexTokenExisted -Backup $script:CodexTokenBackup -Path $script:CodexTokenPath -OriginalLabel 'provider token' -CreatedLabel 'Codex provider token'\n}\n\nfunction Complete-SetupCodexFiles {\n  Remove-SetupOlderBackups -Path $script:CodexConfigPath -Keep $script:CodexConfigBackup\n  Remove-SetupOlderBackups -Path $script:CodexTokenPath -Keep $script:CodexTokenBackup\n  if ($script:CodexTokenBackup -and (Test-Path -LiteralPath $script:CodexTokenBackup)) {\n    Remove-Item -LiteralPath $script:CodexTokenBackup -Force -ErrorAction Stop\n  }\n  $script:CodexTokenBackup = $null\n}\n\n# Drive `codex app-server` over redirected stdin/stdout/stderr: initialize ->\n# initialized -> config/batchWrite. stderr is drained asynchronously so a chatty\n# server cannot fill the pipe buffer and deadlock. Each response read is bounded\n# by the remaining deadline; a timeout terminates the process tree. Unrelated\n# notifications are demultiplexed by id. Returns the batchWrite result object.\nfunction Invoke-SetupCodexAppServerBatchWrite {\n  param([string]$Exe, $Edits, [int]$TimeoutSeconds)\n  $startInfo = New-Object System.Diagnostics.ProcessStartInfo\n  $startInfo.FileName = $Exe\n  $startInfo.Arguments = 'app-server --listen stdio://'\n  $startInfo.UseShellExecute = $false\n  $startInfo.CreateNoWindow = $true\n  $startInfo.RedirectStandardInput = $true\n  $startInfo.RedirectStandardOutput = $true\n  $startInfo.RedirectStandardError = $true\n  $process = New-Object System.Diagnostics.Process\n  $process.StartInfo = $startInfo\n  if (-not $process.Start()) { Stop-Setup \"failed to start the Codex app-server.\" }\n  $stderrTask = $process.StandardError.ReadToEndAsync()\n  $watch = [System.Diagnostics.Stopwatch]::StartNew()\n  $budgetMs = $TimeoutSeconds * 1000\n  $result = $null\n  try {\n    $readMatching = {\n      param([int]$WantId)\n      while ($true) {\n        $remaining = $budgetMs - $watch.ElapsedMilliseconds\n        if ($remaining -le 0) { Stop-Setup \"the Codex app-server timed out before confirming the configuration.\" }\n        $task = $process.StandardOutput.ReadLineAsync()\n        if (-not $task.Wait([int]$remaining)) { Stop-Setup \"the Codex app-server timed out before confirming the configuration.\" }\n        $line = $task.GetAwaiter().GetResult()\n        if ($null -eq $line) { Stop-Setup \"the Codex app-server exited before confirming the configuration.\" }\n        if ([string]::IsNullOrWhiteSpace($line)) { continue }\n        try { $msg = $line | ConvertFrom-Json } catch { Stop-Setup \"the Codex app-server returned a malformed response.\" }\n        if ($msg.id -ne $WantId) { continue }\n        if ($null -ne $msg.error) { Stop-Setup \"the Codex app-server reported an error writing the configuration.\" }\n        return $msg.result\n      }\n    }\n    $initReq = @{ jsonrpc = '2.0'; id = 1; method = 'initialize'; params = @{ clientInfo = @{ name = 'floway-setup'; title = $null; version = '1' }; capabilities = $null } } | ConvertTo-Json -Depth 10 -Compress\n    $process.StandardInput.WriteLine($initReq)\n    [void](& $readMatching 1)\n    $process.StandardInput.WriteLine('{\"jsonrpc\":\"2.0\",\"method\":\"initialized\"}')\n    $batchReq = @{ jsonrpc = '2.0'; id = 2; method = 'config/batchWrite'; params = @{ edits = $Edits } } | ConvertTo-Json -Depth 10 -Compress\n    $process.StandardInput.WriteLine($batchReq)\n    $result = (& $readMatching 2)\n  } finally {\n    try { $process.StandardInput.Close() } catch { }\n    if (-not $process.WaitForExit(1000)) {\n      Stop-SetupProcessTree $process\n      $process.WaitForExit()\n    }\n    $null = $stderrTask.GetAwaiter().GetResult()\n  }\n  return $result\n}\n\n# Build the base-config edit batch and write it through the app-server. Model\n# and effort are opaque, forwarded verbatim, and cleared with JSON null ($null)\n# when unset. A batch status of `ok` or `okOverridden` confirms the intended\n# base config; `okOverridden` is reported with its non-secret layer metadata.\nfunction Write-SetupCodexConfig {\n  param([string]$Exe)\n  $codexBase = ($SetupEndpoint.TrimEnd('/')) + '/azure-api.codex'\n  $runningOnWindows = Test-SetupIsWindows\n  $auth = if ($runningOnWindows) {\n    [ordered]@{\n      command = 'powershell'\n      args = @('-NoProfile', '-Command', '$h = if ($env:CODEX_HOME) { $env:CODEX_HOME } else { Join-Path $HOME ''.codex'' }; [IO.File]::ReadAllText((Join-Path $h ''floway-token''))')\n    }\n  } else {\n    [ordered]@{\n      command = 'sh'\n      args = @('-c', 'cat \"${CODEX_HOME:-$HOME/.codex}/floway-token\"')\n    }\n  }\n  # Command auth opts a provider into online model refresh. The actor marker\n  # enables Codex's client-owned search and image extensions for this provider.\n  # https://github.com/openai/codex/blob/1bbdb32789e1f79932df44941236ea3658f6e965/codex-rs/models-manager/src/manager.rs#L413-L415\n  # https://github.com/openai/codex/blob/1bbdb32789e1f79932df44941236ea3658f6e965/codex-rs/model-provider-info/src/lib.rs#L396-L408\n  # standalone_web_search is under development, so its explicit opt-in is\n  # paired with the top-level warning suppression instead of warning every run.\n  # https://github.com/openai/codex/blob/24e9b849fad8f506971dfa0313dbdea8abd90112/codex-rs/features/src/lib.rs#L901-L905\n  # https://github.com/openai/codex/blob/24e9b849fad8f506971dfa0313dbdea8abd90112/codex-rs/features/src/lib.rs#L1393-L1439\n  $edits = @(\n    @{ keyPath = 'model_provider'; mergeStrategy = 'replace'; value = 'floway' },\n    @{ keyPath = 'suppress_unstable_features_warning'; mergeStrategy = 'replace'; value = $true },\n    @{ keyPath = 'model_providers.floway.name'; mergeStrategy = 'replace'; value = 'Floway' },\n    @{ keyPath = 'model_providers.floway.base_url'; mergeStrategy = 'replace'; value = $codexBase },\n    @{ keyPath = 'model_providers.floway.auth'; mergeStrategy = 'replace'; value = $auth },\n    @{ keyPath = 'model_providers.floway.wire_api'; mergeStrategy = 'replace'; value = 'responses' },\n    @{ keyPath = 'model_providers.floway.supports_websockets'; mergeStrategy = 'replace'; value = $true },\n    @{ keyPath = 'model_providers.floway.http_headers'; mergeStrategy = 'replace'; value = @{ 'x-openai-actor-authorization' = '1' } },\n    @{ keyPath = 'features.apps'; mergeStrategy = 'replace'; value = $false },\n    @{ keyPath = 'features.standalone_web_search'; mergeStrategy = 'replace'; value = $true },\n    @{ keyPath = 'model'; mergeStrategy = 'replace'; value = $SetupCodexModel },\n    @{ keyPath = 'model_reasoning_effort'; mergeStrategy = 'replace'; value = $SetupCodexReasoningEffort }\n  )\n  $timeoutSeconds = Get-SetupTimeoutSeconds 60\n  $result = Invoke-SetupCodexAppServerBatchWrite -Exe $Exe -Edits $edits -TimeoutSeconds $timeoutSeconds\n  $status = [string]$result.status\n  if ($status -eq 'okOverridden') {\n    $message = if ($result.overriddenMetadata -and $result.overriddenMetadata.message) { [string]$result.overriddenMetadata.message } else { 'an override layer applies' }\n    $layer = 'unknown'\n    if ($result.overriddenMetadata -and $result.overriddenMetadata.overridingLayer -and $result.overriddenMetadata.overridingLayer.name) {\n      $layer = [string]$result.overriddenMetadata.overridingLayer.name.type\n    }\n    Write-SetupWarn \"Codex configuration is overridden by a higher-precedence layer ($message; layer: $layer).\"\n  } elseif ($status -ne 'ok') {\n    Stop-Setup \"the Codex app-server did not confirm the configuration (status: $status).\"\n  }\n  $filePath = [string]$result.filePath\n  if ([string]::IsNullOrWhiteSpace($filePath)) {\n    Stop-Setup \"the Codex app-server did not report the written config path.\"\n  }\n  return $filePath\n}\n\n# Store the selected API key as a provider-scoped command-auth token. The private\n# stage is validated byte-for-byte, then atomically replaced. auth.json is an\n# account-owned Codex file and is never read or changed here.\nfunction Write-SetupCodexToken {\n  $stage = \"$($script:CodexTokenPath).floway-stage.$PID\"\n  try {\n    [System.IO.File]::Create($stage).Dispose()\n    Protect-SetupFile $stage\n    [System.IO.File]::WriteAllText($stage, $SetupApiKey, (New-Object System.Text.UTF8Encoding($false)))\n    if ([System.IO.File]::ReadAllText($stage) -cne $SetupApiKey) {\n      Stop-Setup \"staged Codex provider token failed validation.\"\n    }\n    $runningOnWindows = Test-SetupIsWindows\n    if ($script:CodexTokenExisted -and $runningOnWindows) {\n      # File.Replace preserves the destination ACL, so tighten it first.\n      Protect-SetupFile $script:CodexTokenPath\n      # PowerShell binds ordinary $null to String.Empty for a .NET string\n      # parameter; NullString passes an actual null backup path.\n      # https://learn.microsoft.com/en-us/dotnet/api/system.management.automation.language.nullstring\n      [System.IO.File]::Replace($stage, $script:CodexTokenPath, [System.Management.Automation.Language.NullString]::Value)\n    } else {\n      Move-Item -LiteralPath $stage -Destination $script:CodexTokenPath -Force\n    }\n  } catch {\n    if (Test-Path -LiteralPath $stage) { Remove-Item -LiteralPath $stage -Force }\n    throw\n  }\n}\n\nfunction Write-SetupCodexVersion {\n  param([string]$Exe)\n  $timeoutSeconds = Get-SetupTimeoutSeconds 30\n  $version = Invoke-SetupProcess -Exe $Exe -Arguments @('--version') -TimeoutSeconds $timeoutSeconds -TimeoutMessage '``codex --version`` timed out.'\n  if ($version.ExitCode -ne 0) { Stop-Setup \"``codex --version`` failed.\" }\n  Write-SetupInfo \"Codex version: $($version.Output.Trim())\"\n}\n\n# Install, then configure Codex as one transactional config/token write. A\n# freshly installed CLI is never uninstalled when configuration fails.\nfunction Set-SetupAgent {\n  Write-SetupAgentNotice 'Installing' 'Codex'\n  # Upstream installs into these user-local candidates by default:\n  # https://github.com/openai/codex/blob/d3fc1950a920f98e7fa9f11056667cdf911c38df/scripts/install/install.sh\n  $candidates = @(\n    (Join-Path $HOME '.local/bin/codex'),\n    (Join-Path $HOME '.local/bin/codex.exe')\n  )\n  if ($env:USERPROFILE) { $candidates += (Join-Path $env:USERPROFILE '.local\\bin\\codex.exe') }\n  $exe = Get-SetupCliExe -Name codex -Label Codex -Candidates $candidates\n  if (-not $exe) {\n    Install-SetupCodex\n    $exe = Get-SetupCliExe -Name codex -Label Codex -Candidates $candidates\n    if (-not $exe) { Stop-Setup \"Codex CLI is unavailable and could not be installed.\" }\n  } else {\n    Write-SetupInfo 'Codex is already installed.'\n  }\n  Write-SetupCodexVersion -Exe $exe\n\n  Write-SetupAgentNotice 'Configuring' 'Codex'\n  $script:CodexHomeDir = if ($env:CODEX_HOME) { $env:CODEX_HOME } else { Join-Path $HOME '.codex' }\n  $script:CodexConfigPath = Join-Path $script:CodexHomeDir 'config.toml'\n  $script:CodexTokenPath = Join-Path $script:CodexHomeDir 'floway-token'\n  if (-not (Test-Path -LiteralPath $script:CodexHomeDir)) {\n    New-Item -ItemType Directory -Path $script:CodexHomeDir -Force | Out-Null\n  }\n  Backup-SetupCodexFiles\n  try {\n    Write-SetupCodexToken\n  } catch {\n    Write-SetupWarn \"Codex provider-token staging failed; rolling back configuration and token.\"\n    Restore-SetupCodexFiles\n    throw\n  }\n  try {\n    $writtenConfigPath = Write-SetupCodexConfig -Exe $exe\n  } catch {\n    Write-SetupWarn \"Codex configuration failed; rolling back configuration and token.\"\n    Restore-SetupCodexFiles\n    throw\n  }\n  try {\n    Complete-SetupCodexFiles\n  } catch {\n    Write-SetupWarn \"Codex backup cleanup failed; rolling back configuration and token.\"\n    Restore-SetupCodexFiles\n    throw\n  }\n  Write-SetupInfo ('Written to `' + $writtenConfigPath + '`.')\n  Write-SetupInfo ('Written to `' + $script:CodexTokenPath + '`.')\n  Write-SetupAgentNotice 'Completed Agent Setup' 'Codex'\n}\n\n\n$global:LASTEXITCODE = Main 'Codex'\n";
